"use client"
import { DashboardHeader } from "./components/dashboard-header";
import { StatsCards } from "./components/cards-status";
import { useEffect, useState } from "react";
import { createClient } from "@supabase/supabase-js";
import type { Ordem } from "../../(pages)/ordens/types";
import { OrdensList } from "./components/ordens-lista";
import axios from "axios";
import { Pagination } from "../../(pages)/veiculos/types";

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
);

export default function Page() {
  const [ordens, setOrdens] = useState<Ordem[]>([]);
  const [activeTab, setActiveTab] = useState("abertas");
  const [isLoading, setIsLoading] = useState(false);

  const OPEN_STATUSES = [
    "AGUARDANDO_CHECKLIST",
    "ORCAMENTO",
    "ORCAMENTO_RECUSADO",
    "APROVACAO_ORCAMENTO",
    "ORCAMENTO_APROVADO",
    "EM_ANDAMENTO",
    "PAGAMENTO",
  ];

  const FINISHED_STATUSES = ["CONCLUIDO", "SEM_COBRANCA", "CANCELADO"];

  const [pagination, setPagination] = useState<Pagination>({
    page: 1,
    limit: 50,
    total: 0,
    pageCount: 0,
    totalPages: 0,
  });

  // Função para buscar ordens
  const fetchOrdens = async (page: number, limit: number, tabOverride?: string) => {
    setIsLoading(true);
    try {
      const currentTab = tabOverride ?? activeTab;
      const statuses =
        currentTab === "abertas" ? OPEN_STATUSES : FINISHED_STATUSES;

      const { data } = await axios.get<{ items: Ordem[], total: number, totalPages: number, pageCount: number }>("/api/ordens/root", {
        params: {
          page,
          limit,
          statuses: statuses.join(","),
        },
      });

      setOrdens(data.items ?? []);
      setPagination((prev) => ({
        ...prev,
        page,
        limit,
        total: data.total,
        totalPages: data.totalPages,
        pageCount: data.pageCount,
      }));
    } catch (err: any) {
      if (err?.name === "CanceledError" || err?.code === "ERR_CANCELED") return;
      console.error("Erro ao buscar ordens:", err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleGetOrdens = (page: number, limit: number) => {
    void fetchOrdens(page, limit);
  };

  // ✅ 1) Carrega um snapshot inicial (pra UPDATE começar a fazer sentido)
  // E recarrega quando muda a TAB (reseta para pagina 1)
  useEffect(() => {
    const controller = new AbortController();
    
    // Sempre que mudar a tab, reseta pra pagina 1
    void fetchOrdens(1, 50);

    return () => {
      controller.abort();
    };
  }, [activeTab]);

  // ✅ 2) Realtime com UPSERT no state (UPDATE também “entra” se não existir)
  useEffect(() => {
    const canalOs = supabase
      .channel("realtime:ordemservico")
      .on(
        "postgres_changes",
        { event: "*", schema: "public", table: "ordemservico" },
        async (payload) => {
          console.log("[REALTIME]", payload.eventType, payload);

          const tipo = payload.eventType;
          const currentStatuses =
            activeTab === "abertas" ? OPEN_STATUSES : FINISHED_STATUSES;

          if (tipo === "INSERT" || tipo === "UPDATE") {
            const partial = payload.new as Ordem;
            if (!partial.id) return;

            // Busca os dados completos da API para ter os joins (cliente, veiculo, etc)
            try {
              const { data } = await axios.get<{ items: Ordem[] }>(
                "/api/ordens/root",
                {
                  params: {
                    q: String(partial.id),
                    limit: 1,
                    // Se quiser garantir que venha mesmo se status mudou, 
                    // talvez não devêssemos passar 'statuses' aqui. 
                    // O endpoint root filtra por statuses se passar params.
                    // Se não passar, vem "TODAS" se não mandar nada?
                    // O endpoint diz: const status = ... || "TODAS".
                    // Então sem params, busca em "TODAS".
                  },
                },
              );
              
              const incoming = data.items.find((o) => o.id === partial.id);

              // Se não achou na API (ex: soft deleted e a API filtra, ou algum erro), aborta
              if (!incoming) {
                 // Se foi soft delete no bando, pode ser que a API não retorne.
                 // Mas vamos checar is_deleted do payload primeiro.
                 if ((partial as any).is_deleted) {
                    setOrdens((atual) => atual.filter((o) => o.id !== partial.id));
                 }
                 return;
              }

              // soft delete check (caso venha no objeto completo também)
              if ((incoming as any).is_deleted) {
                setOrdens((atual) => atual.filter((o) => o.id !== incoming.id));
                return;
              }

              // Verifica se o status do incoming faz parte da tab atual
              const isValidForTab = currentStatuses.includes(
                incoming.status as string,
              );

              if (!isValidForTab) {
                // Se não for válido para a tab atual, removemos se existir
                setOrdens((atual) => atual.filter((o) => o.id !== incoming.id));
                return;
              }

              setOrdens((atual) => {
                const idx = atual.findIndex((o) => o.id === incoming.id);
                if (idx === -1) return [incoming, ...atual]; // ✅ entra no array
                const copia = [...atual];
                copia[idx] = incoming;
                return copia;
              });

            } catch (err) {
              console.error("Erro ao buscar ordem atualizada via realtime:", err);
            }
            return;
          }

          if (tipo === "DELETE") {
            const antigo = payload.old as Partial<Ordem>;
            if (antigo?.id == null) return;
            setOrdens((atual) => atual.filter((o) => o.id !== antigo.id));
          }
        },
      )
      .subscribe((status) => {
        console.log("STATUS:", status); // SUBSCRIBED / CLOSED / CHANNEL_ERROR ...
      });

    return () => {
      supabase.removeChannel(canalOs);
    };
  }, [activeTab]);

  return (
    <div className="min-h-screen bg-background">
      <DashboardHeader />

      <main className="p-6 space-y-6">
        <div className="flex flex-col gap-2">
          <h1 className="text-2xl font-bold tracking-tight text-balance">
            Dashboard
          </h1>
          <p className="text-muted-foreground">
            Acompanhe suas ordens de serviço em tempo real
          </p>
        </div>
        <StatsCards />
        <OrdensList
        handleGetOrdens={handleGetOrdens}
        pagination={pagination}
          isLoading={isLoading}
          ordens={ordens}
          activeTab={activeTab}
          onTabChange={setActiveTab}
        />
      </main>
    </div>
  );
}

import CustomerSelect from "@/app/(app)/components/customerSelect";
import { Button } from "@/components/ui/button";
import { Calendar } from "@/components/ui/calendar";
import { Checkbox } from "@/components/ui/checkbox";
import {
DialogClose,
DialogContent,
DialogDescription,
DialogFooter,
DialogHeader,
DialogTitle,
} from "@/components/ui/dialog";
import {
DrawerClose,
DrawerContent,
DrawerDescription,
DrawerFooter,
DrawerHeader,
DrawerTitle,
} from "@/components/ui/drawer";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
Popover,
PopoverContent,
PopoverTrigger,
} from "@/components/ui/popover";
import {
Select,
SelectContent,
SelectItem,
SelectTrigger,
SelectValue,
} from "@/components/ui/select";
import { Separator } from "@/components/ui/separator";
import { Switch } from "@/components/ui/switch";
import { cn } from "@/lib/utils";
import formatarEmReal from "@/utils/formatarEmReal";
import axios,{ isAxiosError } from "axios";
import { CalendarIcon,Info,Minus,Plus,Save } from "lucide-react";
import { Dispatch,SetStateAction,useEffect,useState } from "react";
import { toast } from "sonner";
import { useCategoriasTransacao } from "../../hooks/use-categoria-transacao";
import {
Banco,
Metodo_pagamento,
NewTransaction,
Tipo_transacao,
TransactionCustomer
} from "../../types";
import { formatCpfCnpj } from "../../utils";
import ValueInput from "./valueInput";

interface ParcelaFormulario {
  id: number;
  dataVencimento?: Date;
  valor: number;
}

function addMonths(date: Date, months: number) {
  const next = new Date(date);
  next.setMonth(next.getMonth() + months);
  return next;
}

function distribuirValoresIguais(total: number, quantidade: number) {
  if (quantidade <= 0) return [];

  const totalCentavos = Math.round((total || 0) * 100);
  const valorBase = Math.floor(totalCentavos / quantidade);
  const resto = totalCentavos - valorBase * quantidade;

  return Array.from({ length: quantidade }, (_, index) => {
    const centavos = valorBase + (index < resto ? 1 : 0);
    return centavos / 100;
  });
}

function toCentavos(value: number | undefined) {
  return Math.round((value || 0) * 100);
}

function toDateOnly(date: Date) {
  return new Date(date.getFullYear(), date.getMonth(), date.getDate());
}

function formatDateLabel(date?: Date) {
  return date ? date.toLocaleDateString("pt-BR") : "Selecionar data";
}

function DatePickerField({
  value,
  onChange,
  disabled = false,
}: {
  value?: Date;
  onChange: (date: Date | undefined) => void;
  disabled?: boolean;
}) {
  return (
    <Popover>
      <PopoverTrigger asChild>
        <Button
          type="button"
          variant="outline"
          disabled={disabled}
          className={cn(
            "w-full justify-start text-left font-normal",
            !value && "text-muted-foreground",
          )}
        >
          <CalendarIcon className="mr-2 h-4 w-4" />
          {formatDateLabel(value)}
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-auto p-0" align="start">
        <Calendar
          mode="single"
          selected={value ? toDateOnly(value) : undefined}
          onSelect={(date) => onChange(date ? toDateOnly(date) : undefined)}
          initialFocus
        />
      </PopoverContent>
    </Popover>
  );
}

interface RegisterContentProps {
  osId?: number | undefined;
  vendaId?: number | undefined;
  setSelectedTransactionId?: (value: number | undefined) => void;
  newTransaction: NewTransaction;
  setNewTransaction: Dispatch<SetStateAction<NewTransaction>>;
  dialogOpen: boolean | undefined;
  selectedCustomer: TransactionCustomer | undefined;
  setSelectedCustomer: (value: TransactionCustomer | undefined) => void;
  handleGetTransactions?: (pageNumber?: number) => void;
  setOpen?: (value: boolean) => void;
  isDesktop?: boolean;
}

export default function RegisterContent({
  setSelectedTransactionId,
  newTransaction,
  setNewTransaction,
  dialogOpen,
  selectedCustomer,
  osId,
  vendaId,
  setSelectedCustomer,
  handleGetTransactions,
  setOpen,
  isDesktop,
}: RegisterContentProps) {
  const [isCustomerSelectOpen, setIsCustomerSelectOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [, setIsLoadingBanks] = useState(false);
  const [banks, setBanks] = useState<Banco[]>([]);
  const [isChecked, setIsChecked] = useState(false);
  const [pagoPeloMesmo, setPagoPeloMesmo] = useState(false);
  const [clienteMesmoCache, setClienteMesmoCache] = useState<
    TransactionCustomer | undefined
  >(undefined);
  const [parcelasIguais, setParcelasIguais] = useState(false);
  const [parcelasDetalhadas, setParcelasDetalhadas] = useState<
    ParcelaFormulario[]
  >([]);
  const { categorias, loadingCategorias, errorCategorias } =
    useCategoriasTransacao();
  const canManageParcelas =
    newTransaction.metodopagamento === Metodo_pagamento.BOLETO &&
    !!newTransaction.pendente;
  const canUseMesmoCliente = Boolean(osId || vendaId);

  const handleChange = (
    field: keyof NewTransaction,
    value: string | number | null,
  ) => {
    setNewTransaction({ ...newTransaction, [field]: value });
  };

  const setParcelas = (
    updater: ParcelaFormulario[] | ((prev: ParcelaFormulario[]) => ParcelaFormulario[]),
  ) => {
    setParcelasDetalhadas((prev) =>
      typeof updater === "function" ? updater(prev) : updater,
    );
  };

  const handleGetBanks = async () => {
    setIsLoadingBanks(true);
    try {
      const response = await axios.get("/api/banks", {});
      if (response.status === 200) {
        const { data } = response;
        setBanks(data.data);
      }
    } catch {
    } finally {
      setIsLoadingBanks(false);
    }
  };

  const buscarClienteMesmo = async (): Promise<
    TransactionCustomer | undefined
  > => {
    if (clienteMesmoCache?.id) {
      return clienteMesmoCache;
    }

    try {
      if (osId) {
        const response = await axios.get(`/api/ordens/${osId}`);
        const cliente = response.data?.cliente ?? response.data?.os?.cliente;
        if (!cliente?.id) return undefined;

        const transactionCustomer = {
          id: cliente.id,
          nome: cliente.nomerazaosocial ?? cliente.nome ?? "",
          cpfcnpj: cliente.cpfcnpj ?? "",
        };

        setClienteMesmoCache(transactionCustomer);
        return transactionCustomer;
      }

      if (vendaId) {
        const response = await axios.get(`/api/venda/${vendaId}`);
        const cliente = response.data?.data?.cliente;
        if (!cliente?.id) return undefined;

        const transactionCustomer = {
          id: cliente.id,
          nome: cliente.nomerazaosocial ?? cliente.nome ?? "",
          cpfcnpj: cliente.cpfcnpj ?? "",
        };

        setClienteMesmoCache(transactionCustomer);
        return transactionCustomer;
      }
    } catch {
      toast.error("NÃ£o foi possÃ­vel carregar o cliente vinculado.");
    }

    return undefined;
  };

  const aplicarClienteMesmo = async () => {
    const transactionCustomer = await buscarClienteMesmo();
    if (transactionCustomer?.id) {
      setSelectedCustomer(transactionCustomer);
      setNewTransaction((prev) => ({
        ...prev,
        cliente_id: transactionCustomer.id,
        nomepagador: transactionCustomer.nome,
        cpfcnpjpagador: transactionCustomer.cpfcnpj,
      }));
      return;
    }

    try {
      if (osId) {
        const response = await axios.get(`/api/ordens/${osId}`);
        const cliente = response.data?.cliente ?? response.data?.os?.cliente;
        if (!cliente?.id) return;

        const transactionCustomer = {
          id: cliente.id,
          nome: cliente.nomerazaosocial ?? cliente.nome ?? "",
          cpfcnpj: cliente.cpfcnpj ?? "",
        };

        setSelectedCustomer(transactionCustomer);
        setNewTransaction((prev) => ({
          ...prev,
          cliente_id: transactionCustomer.id,
          nomepagador: transactionCustomer.nome,
          cpfcnpjpagador: transactionCustomer.cpfcnpj,
        }));
        return;
      }

      if (vendaId) {
        const response = await axios.get(`/api/venda/${vendaId}`);
        const cliente = response.data?.data?.cliente;
        if (!cliente?.id) return;

        const transactionCustomer = {
          id: cliente.id,
          nome: cliente.nomerazaosocial ?? cliente.nome ?? "",
          cpfcnpj: cliente.cpfcnpj ?? "",
        };

        setSelectedCustomer(transactionCustomer);
        setNewTransaction((prev) => ({
          ...prev,
          cliente_id: transactionCustomer.id,
          nomepagador: transactionCustomer.nome,
          cpfcnpjpagador: transactionCustomer.cpfcnpj,
        }));
      }
    } catch {
      toast.error("Não foi possível carregar o cliente vinculado.");
    }
  };

  useEffect(() => {
    if (selectedCustomer) {
      setNewTransaction((prev) => ({
        ...prev,
        nomepagador: selectedCustomer.nome,
        cpfcnpjpagador: selectedCustomer.cpfcnpj,
        cliente_id: selectedCustomer.id,
      }));
    }
  }, [setNewTransaction, selectedCustomer]);

  useEffect(() => {
    if (!canUseMesmoCliente) {
      setPagoPeloMesmo(false);
      setClienteMesmoCache(undefined);
      return;
    }
    setPagoPeloMesmo(true);
    void (async () => {
      const transactionCustomer = await buscarClienteMesmo();
      if (!transactionCustomer?.id) return;

      setSelectedCustomer(transactionCustomer);
      setNewTransaction((prev) => ({
        ...prev,
        cliente_id: transactionCustomer.id,
        nomepagador: transactionCustomer.nome,
        cpfcnpjpagador: transactionCustomer.cpfcnpj,
      }));
    })();
  }, [canUseMesmoCliente, osId, vendaId, setNewTransaction, setSelectedCustomer]);

  useEffect(() => {
    if (!pagoPeloMesmo) return;
    void aplicarClienteMesmo();
  }, [pagoPeloMesmo]);

  useEffect(() => {
    if (!dialogOpen || !canUseMesmoCliente) return;

    setPagoPeloMesmo(true);

    void (async () => {
      const transactionCustomer = await buscarClienteMesmo();
      if (!transactionCustomer?.id) return;

      setSelectedCustomer(transactionCustomer);
      setNewTransaction((prev) => ({
        ...prev,
        cliente_id: transactionCustomer.id,
        nomepagador: transactionCustomer.nome,
        cpfcnpjpagador: transactionCustomer.cpfcnpj,
      }));
    })();
  }, [dialogOpen, canUseMesmoCliente, osId, vendaId, setNewTransaction, setSelectedCustomer]);

  const handleCreateTransaction = async () => {
    setIsSubmitting(true);
    try {
      let parcelasPayload: Array<{ data: Date; valor: number }> | undefined;

      if (!newTransaction.banco_id) {
        toast.error("Selecione um banco.");
        return;
      }

      if (canManageParcelas) {
        if (parcelasDetalhadas.length === 0) {
          toast.error("Adicione ao menos uma parcela.");
          return;
        }

        if (
          parcelasDetalhadas.some(
            (parcela) =>
              !parcela.valor ||
              parcela.valor <= 0 ||
              !parcela.dataVencimento,
          )
        ) {
          toast.error("As parcelas ainda não foram geradas corretamente.");
          return;
        }

        if (parcelasDetalhadas.some((parcela) => !parcela.valor || parcela.valor <= 0)) {
          toast.error("Todas as parcelas precisam ter valor maior que zero.");
          return;
        }

        const somaParcelas = parcelasDetalhadas.reduce(
          (acc, parcela) => acc + toCentavos(parcela.valor),
          0,
        );
        const valorTotal = toCentavos(newTransaction.valor);

        if (somaParcelas !== valorTotal) {
          toast.error("A soma das parcelas deve ser igual ao valor total.");
          return;
        }

        parcelasPayload = parcelasDetalhadas.map((parcela) => ({
          data: parcela.dataVencimento!,
          valor: parcela.valor,
        }));
      }

      const endpoint = osId ? "/api/transaction/os" : "/api/transaction";

      const response = await axios.post(endpoint, {
        newTransaction: {
          ...newTransaction,
          data: parcelasDetalhadas[0]?.dataVencimento ?? newTransaction.data,
        },
        parcelasDetalhadas: parcelasPayload,
      });

      if (response.status === 201) {
        const created = response.data?.data ?? response.data;

        toast.success("Sucesso!", {
          description: "Transação registrada.",
          duration: 2000,
        });

        // se existir, seta o id (fluxo fora de OS)
        setSelectedTransactionId?.(
          Array.isArray(created) ? created[0]?.id : created?.id,
        );

        // recarrega a lista da OS (quando veio por OS)
        handleGetTransactions?.();

        // fecha SEMPRE que criar
        setOpen?.(false);

        // opcional: limpar o formulário
        setNewTransaction({});
        setSelectedCustomer?.(undefined);
        setParcelasDetalhadas([]);
        setParcelasIguais(false);
      }
    } catch (error) {
      if (isAxiosError(error)) {
        toast("Erro", {
          description: error.response?.data?.error,
          duration: 2000,
        });
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  useEffect(() => {
    handleGetBanks();
  }, []);

  useEffect(() => {
    setNewTransaction({
      ...newTransaction,
      valorLiquido: newTransaction.valor,
    });
    setIsChecked(false);
  }, [, newTransaction.metodopagamento]);

  useEffect(() => {
    if (!canManageParcelas) {
      setParcelasDetalhadas([]);
      setParcelasIguais(false);
    }
  }, [canManageParcelas]);

  useEffect(() => {
    if (!canManageParcelas) return;

    setParcelasDetalhadas((prev) => {
      const quantidade = Math.max(1, prev.length || 1);
      const valoresPadrao = distribuirValoresIguais(
        newTransaction.valor ?? 0,
        quantidade,
      );
      const dataBase = newTransaction.data ?? new Date();

      return Array.from({ length: quantidade }, (_, index) => ({
        id: prev[index]?.id ?? Date.now() + index,
        dataVencimento:
          prev[index]?.dataVencimento ?? addMonths(dataBase, index),
        valor: parcelasIguais
          ? valoresPadrao[index] ?? 0
          : prev[index]?.valor ?? valoresPadrao[index] ?? 0,
      }));
    });
  }, [
    canManageParcelas,
    parcelasIguais,
    newTransaction.data,
    newTransaction.valor,
  ]);

  useEffect(() => {
    if (!isChecked) {
      setNewTransaction({
        ...newTransaction,
        valorLiquido: newTransaction.valor,
      });
    }
  }, [newTransaction.valor]);

  useEffect(() => {
    if (
      newTransaction.tipo === Tipo_transacao.SAQUE ||
      newTransaction.tipo === Tipo_transacao.DEPOSITO
    ) {
      setNewTransaction({
        ...newTransaction,
        pendente: false,
      });
    }
  }, [newTransaction.tipo]);

  useEffect(() => {
    setNewTransaction({
      ...newTransaction,
      data: undefined,
    });
  }, [newTransaction.pendente]);

  const Content = isDesktop ? DialogContent : DrawerContent;
  const Header = isDesktop ? DialogHeader : DrawerHeader;
  const Footer = isDesktop ? DialogFooter : DrawerFooter;
  const Title = isDesktop ? DialogTitle : DrawerTitle;
  const Description = isDesktop ? DialogDescription : DrawerDescription;
  const Close = isDesktop ? DialogClose : DrawerClose;

  return (
    <Content
      className={
        isDesktop
          ? `
        h-svh w-[100dvw] max-w-[100dvw] p-0 overflow-hidden min-w-0
        sm:max-w-[1100px] sm:max-h-[850px] sm:w-[95vw] sm:min-w-0
      `
          : `h-[100dvh] min-h-dvh mt-0 rounded-none max-h-none flex flex-col`
      }
    >
      <div className="flex h-full min-h-0 flex-col">
        <Header className="shrink-0 px-6 py-4 border-b-1">
          {osId && (
            <Title>
              OS #{osId}{" "}
              <span className="text-muted-foreground text-sm font-light">
                | TRANSAÇÃO
              </span>
            </Title>
          )}
          {vendaId && (
            <Title>
              Venda #{vendaId}{" "}
              <span className="text-muted-foreground text-sm font-light">
                | TRANSAÇÃO
              </span>
            </Title>
          )}
          {!osId && !vendaId && <Title>Nova Transação</Title>}
          <Description>Preencha dados para registrar uma transação</Description>
        </Header>
        <div className="h-full min-h-0 overflow-hidden">
          <div className="h-full min-h-0 overflow-auto px-6 py-4 space-y-4 bg-background">
            {/* dados da transação */}
            <div className="space-y-4 grid sm:grid-cols-3 gap-4">
              <div className="space-y-2 w-full">
                <Label htmlFor="tipo">Tipo</Label>
                {osId || vendaId ? (
                  <Select
                    disabled
                    value={"RECEITA"}
                    onValueChange={(v) => handleChange("tipo", v)}
                  >
                    <SelectTrigger className="w-full">
                      <SelectValue placeholder="Selecione" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="RECEITA">RECEITA</SelectItem>
                    </SelectContent>
                  </Select>
                ) : (
                  <Select
                    value={newTransaction.tipo || ""}
                    onValueChange={(v) => handleChange("tipo", v)}
                  >
                    <SelectTrigger className="w-full">
                      <SelectValue placeholder="Selecione" />
                    </SelectTrigger>
                    <SelectContent>
                      {Object.values(Tipo_transacao).map((u) => (
