import OsFinancialDialog from "./osFinancialDialog/osFinancialDialog";

interface OsTableProps {
  ordens: Ordem[];
  pagination: Pagination;
  handleGetOrdens: (
    status: StatusOS,
    pageNumber?: number,
    limit?: number,
    search?: string,
    filters?: PaymentListFilters,
  ) => void;
  isLoading: boolean;
  search: string;
}

export default function OsTable({ ordens, pagination, handleGetOrdens, isLoading, search }: OsTableProps) {
  // ID estável para o Select de "itens por página"
  const [selectedStatus, setSelectedStatus] = useState<StatusOS>("PAGAMENTO");
  const limitUid = React.useId();
  const [openEmissao, setOpenEmissao] = useState(false);
  const [emissaoId, setEmissaoId] = useState<number | undefined>(undefined);
  const [filtersOpen, setFiltersOpen] = useState(false);
  const [filters, setFilters] = useState<PaymentListFilters>({
    cliente: "",
    notaNumero: "",
  });
  const limitListboxId = `${limitUid}-os-limit-listbox`;
  const tabTheme =
    " dark:data-[state=active]:bg-primary data-[state=active]:bg-primary data-[state=active]:text-primary-foreground";
  const hasActiveFilters = Boolean(
    filters.cliente.trim() ||
      filters.notaNumero.trim() ||
      filters.dataInicio ||
      filters.dataFim,
  );

  useEffect(() => {
    handleGetOrdens(selectedStatus, 1, pagination.limit, search, filters);
  }, [selectedStatus]);

  const config = useConfig();

  return (
    <Card className="">
      <CardHeader className="border-b-2 flex flex-col">
        <div className="flex flex-row justify-between gap-3 w-full">
          <CardTitle className="text-lg font-medium">
            Ordens de Serviço{" "}
            <span className="text-muted-foreground text-xs font-mono font-extralight">|EM PAGAMENTO</span>
          </CardTitle>
          <div className="flex items-center gap-2">
            {hasActiveFilters && (
              <Button
                variant="ghost"
                size="sm"
                className="hover:cursor-pointer"
                onClick={() => {
                  const cleared = { cliente: "", notaNumero: "" };
                  setFilters(cleared);
                  handleGetOrdens(selectedStatus, 1, pagination.limit, search, cleared);
                }}
              >
                Limpar filtros
              </Button>
            )}
            <PaymentsFilterSheet
              open={filtersOpen}
              onOpenChange={setFiltersOpen}
              filters={filters}
              onFiltersChange={setFilters}
              onAplicar={() =>
                handleGetOrdens(selectedStatus, 1, pagination.limit, search, filters)
              }
              onLimpar={() => {
                const cleared = { cliente: "", notaNumero: "" };
                setFilters(cleared);
                handleGetOrdens(selectedStatus, 1, pagination.limit, search, cleared);
              }}
            />
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div
            onClick={() =>
              handleGetOrdens(selectedStatus, pagination.page, pagination.limit, search, filters)
            }
            className="flex flex-row space-x-1 items-center hover:cursor-pointer"
          >
            <Loader2 className="w-3 h-3" />
            <span className="text-xs text-muted-foreground"> Recarregar</span>
          </div>
          {hasActiveFilters && (
            <span className="text-xs text-muted-foreground">Filtros ativos</span>
          )}
        </div>
        <Tabs defaultValue="abertas" className="w-full items-center">
          <TabsList className="rounded-b-none">
            <TabsTrigger
              onClick={() => setSelectedStatus("PAGAMENTO")}
              className={" rounded-b-none cursor-pointer" + tabTheme}
              value="abertas"
            >
              Abertas
            </TabsTrigger>
            <TabsTrigger
              onClick={() => setSelectedStatus("CONCLUIDO")}
              className={" rounded-b-none cursor-pointer" + tabTheme}
              value="concluidas"
            >
              Concluídas
            </TabsTrigger>
          </TabsList>
        </Tabs>
      </CardHeader>

      <CardContent className="min-h-[300px] -mt-[24px] px-4 pb-4 pt-0 relative flex flex-col justify-between">
        <EmissaoNotaDialog
          onOpenChange={setOpenEmissao}
          open={openEmissao}
          osId={emissaoId}
        />
        {/* barra superior de loading */}
        <div
          className={`${isLoading && "opacity-100"
            } transition-all opacity-0 h-0.5 bg-slate-400 w-full overflow-hidden absolute left-0 right-0 top-0`}
        >
          <div
            className={`w-1/2 bg-primary h-full absolute left-0 rounded-lg -translate-x-[100%] ${isLoading && "animate-slideIn "
              }`}
          />
        </div>

        <Table className="text-xs mt-6">
          <TableHeader>
            <TableRow>
              <TableHead className="whitespace-nowrap">ID</TableHead>
              <TableHead className="whitespace-nowrap">Nota</TableHead>
              <TableHead>Descrição</TableHead>
              <TableHead>Cliente</TableHead>
              <TableHead>Setor</TableHead>
              <TableHead className="whitespace-nowrap">Pago</TableHead>
              <TableHead className="whitespace-nowrap">Total</TableHead>
              <TableHead className="text-center">Situação</TableHead>
              <TableHead className="text-right whitespace-nowrap w-[90px]">Ações</TableHead>
            </TableRow>
          </TableHeader>

          <TableBody>
            {ordens.length > 0 ? (
              ordens.map((o) => {
                // IDs estáveis por linha para o menu
                const triggerId = `os-row-${o.id}-menu-btn`;
                const menuId = `os-row-${o.id}-menu`;

                return (
                  <TableRow key={o.id} className="hover:cursor-pointer">
                    {/* ... suas outras células (descrição, data etc.) aqui, se/quando tiver ... */}
                    <TableCell>{o.id}</TableCell>
                    <TableCell>{o.notaNumero ?? "-"}</TableCell>
                    <TableCell className="max-w-[320px] truncate">{o.descricao}</TableCell>
                    <TableCell>{o.cliente?.nome}</TableCell>
                    <TableCell>{o.setor?.nome}</TableCell>
                    <TableCell className=" text-blue-300 not-dark:text-blue-700 font-bold">
                      {formatarEmReal(o.transacoes?.reduce((acc, t) => acc + Number(t?.valor ?? 0), 0) ?? 0)}
                    </TableCell>
                    <TableCell>{formatarEmReal(o.orcamentototal || 0)}</TableCell>
                    <TableCell className="text-center">
                      {o.orcamentototal ? (
                        (o.transacoes?.reduce((acc, t) => acc + Number(t?.valor ?? 0), 0) || 0) <
                          (o.orcamentototal || 0) ? (
                          <Badge variant="secondary" className="font-bold text-amber-400">Pagamento</Badge>
                        ) : (
                          <Badge variant="secondary" className="font-bold text-green-400">Faturado</Badge>
                        )
                      ) : (
                        "Orçamento falta valor"
                      )}
                    </TableCell>
                    <TableCell className="text-right whitespace-nowrap w-[90px]">
                      <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                          <Button
                            id={triggerId}
                            aria-controls={menuId}
                            variant="ghost"
                            className="h-8 w-8 p-0 cursor-pointer"
                          >
                            <MoreHorizontal className="h-4 w-4" />
                          </Button>
                        </DropdownMenuTrigger>

                        <DropdownMenuContent id={menuId} aria-labelledby={triggerId} className="space-y-1" align="end">
                          <OsFinancialDialog handleGetOrdens={handleGetOrdens} osId={o.id}>
                            <DropdownMenuItem disabled={o.orcamentototal <= 0} onSelect={(e) => e.preventDefault()}>
                              <DollarSign className="h-4 w-4" />
                              <span>Pagamento</span>
                            </DropdownMenuItem>
                          </OsFinancialDialog>
                          {
                            config?.habilitar_emissao_nfe &&
                            (config?.emissao_nf_ordens_nao_pagas ? o.status === "PAGAMENTO" ||
                              o.status === "CONCLUIDO" : o.status === "CONCLUIDO") && (
                              <DropdownMenuItem
                                onClick={() => {
                                  setEmissaoId(o.id);
                                  setOpenEmissao(true);
                                }}
                              >
                                <FileText className="h-4 w-4" />
                                <span>Emitir NF</span>
                              </DropdownMenuItem>
                            )
                          }

                        </DropdownMenuContent>
                      </DropdownMenu>
                    </TableCell>
                  </TableRow>
                );
              })
            ) : (
              <TableRow>
                <TableCell className="text-center h-20" colSpan={99}>
                  Não existem ordens com este status
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>

        <div className="flex items-center mt-4 justify-between">
          <div className="text-xs text-muted-foreground mr-2 flex flex-nowrap">
            <span>{pagination.limit * (pagination.page - 1) + 1}</span>
            {" - "}
            <span>{pagination.limit * (pagination.page - 1) + ordens.length}</span>
          </div>

          <div className="flex items-center justify-center space-x-2">
            <Button
              variant="outline"
              size="icon"
              className="hover:cursor-pointer"
              onClick={() => handleGetOrdens(selectedStatus, 1, pagination.limit, search, filters)}
              disabled={pagination.page === 1}
            >
              <ChevronsLeft className="h-4 w-4" />
            </Button>

            <Button
              variant="outline"
              size="icon"
              className="hover:cursor-pointer"
              onClick={() => handleGetOrdens(selectedStatus, pagination.page - 1, pagination.limit, search, filters)}
              disabled={pagination.page === 1}
            >
              <ChevronLeftIcon className="h-4 w-4" />
            </Button>

            <span className="text-xs font-medium text-nowrap">
              Pg. {pagination.page} de {pagination.totalPages || 1}
            </span>

            <Button
              className="hover:cursor-pointer"
              variant="outline"
              size="icon"
              onClick={() => handleGetOrdens(selectedStatus, pagination.page + 1, pagination.limit, search, filters)}
              disabled={pagination.page === pagination.totalPages || pagination.totalPages === 0}
            >
              <ChevronRightIcon className="h-4 w-4" />
            </Button>

            <Button
              className="hover:cursor-pointer"
              variant="outline"
              size="icon"
              onClick={() => handleGetOrdens(selectedStatus, pagination.totalPages, pagination.limit, search, filters)}
              disabled={pagination.page === pagination.totalPages || pagination.totalPages === 0}
            >
              <ChevronsRight className="h-4 w-4" />
            </Button>
          </div>

          {/* Select de itens por página com IDs estáveis */}
          <div>
            <Select>
              <SelectTrigger className="hover:cursor-pointer ml-2" aria-controls={limitListboxId}>
                <SelectValue placeholder={`${pagination.limit}`} />
              </SelectTrigger>
              <SelectContent id={limitListboxId}>
                <SelectItem className="hover:cursor-pointer" value="20">
                  {pagination.limit}
                </SelectItem>
                {/* adicione mais opções se desejar (10/20/50/100...) */}
              </SelectContent>
            </Select>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

"use client"
import { useEffect, useState } from "react";
import OsTable from "./components/osTable";
import { Ordem, StatusOS } from "../../ordens/types";
import axios from "axios";
import { PaymentListFilters } from "../components/payments-filter-sheet";

export default function AssistentePagamento (){
    const [ordens, setOrdens] = useState<Ordem[]>([])
    const [pagination, setPagination] = useState({
    total: 0,
    page: 1,
    limit: 20,
    totalPages: 0,
  });
    const [isLoading, setIsLoading] = useState(false)
    const[search, ] = useState("")
    

    const handleGetOrdens = async (
      status: StatusOS,
      pageNumber?: number,
      limit?: number,
      search?: string,
      filters?: PaymentListFilters,
    ) => {
    setIsLoading(true);
    try {
      const response = await axios.get("/api/ordens", {
        params: {
          page: pageNumber || 1,
          limit: limit || pagination.limit,
          q: search || "",
          status: status,
          cliente: filters?.cliente || "",
          notaNumero: filters?.notaNumero || "",
          dateFrom: filters?.dataInicio
            ? filters.dataInicio.toISOString().slice(0, 10)
            : "",
          dateTo: filters?.dataFim
            ? filters.dataFim.toISOString().slice(0, 10)
            : "",
        },
      });
      if (response.status === 200) {
        const { data } = response;
        setOrdens(data.items);
        setPagination({...pagination, limit:data.limit, page: data.page, totalPages:data.totalPages, total: data.total});
      }
    } catch {
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(()=> {
    handleGetOrdens("PAGAMENTO");
  },[])

    return (

    <div className="p-y-4 space-y-4">
        <OsTable
        search={search}
        isLoading={isLoading}
        handleGetOrdens={handleGetOrdens}
        ordens={ordens}
        pagination={pagination}
        />
    </div>

    )
}

import { VendaComItens } from "@/app/(app)/(pages)/(vendas)/historicovendas/types";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { DialogContent,DialogDescription,DialogFooter,DialogHeader,DialogTitle } from "@/components/ui/dialog";
import { DropdownMenu,DropdownMenuContent,DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import { Separator } from "@/components/ui/separator";
import { Table,TableBody,TableCell,TableHead,TableHeader,TableRow } from "@/components/ui/table";
import {
getVendaAnexoCategoriaLabel,
type VendaAnexoCategoria,
} from "@/lib/venda-anexo-categorias";
import formatarEmReal from "@/utils/formatarEmReal";
import { formatDate } from "@/utils/formatDate";
import axios,{ isAxiosError } from "axios";
import { ChevronDown,ExternalLink,FileText,Loader,Loader2,Paperclip,Trash2Icon } from "lucide-react";
import Image from "next/image";
import { useEffect,useState } from "react";
import { toast } from "sonner";
import TransactionDialog from "../../../fluxodecaixa/components/transactionDialog/transactionDialog";
import { Metodo_pagamento,Transaction } from "../../../fluxodecaixa/types";
import DeleteAlert from "./deleteAlert";

interface VendasContentProps {
  vendaId: number;
  IsOpen?: boolean;
}

type VendaAnexo = {
  id: number;
  nome: string;
  tipo?: string | null;
  tamanho?: number | null;
  url: string;
  categoria: VendaAnexoCategoria;
  createdat?: string | null;
};

const PAYMENT_METHOD_LABELS: Record<string, string> = {
  CREDITO: "Credito",
  DEBITO: "Debito",
  DINHEIRO: "Dinheiro",
  PIX: "Pix",
  BOLETO: "Boleto",
  TRANSFERENCIA: "Transferencia",
};

// Ajuste conforme a sua estrutura real

export default function VendasContent({ vendaId, IsOpen }: VendasContentProps) {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isLoadingOs, setIsLoadingOs] = useState(false);
  const [pagination, setPagination] = useState({
    total: 0,
    page: 1,
    limit: 20,
    totalPages: 0,
  });
  const [venda, setVenda] = useState<VendaComItens | undefined>(undefined);
  const [anexos, setAnexos] = useState<VendaAnexo[]>([]);
  const [isLoadingAnexos, setIsLoadingAnexos] = useState(false);
  const [, setIsDeleting] = useState(false);
  const [isAlertOpen, setIsAlertOpen] = useState(false);
  const [open, setOpen] = useState(false);
  const totalPago = transactions?.reduce((acc, t) => acc + Number(t?.valor ?? 0), 0) ?? 0;
  const saldoDevedor = (venda?.valortotal || 0) - totalPago;
  const initialMetodoPagamento = (() => {
    const value = String(venda?.forma_pagamento ?? "").toUpperCase();
    return Object.values(Metodo_pagamento).includes(value as Metodo_pagamento)
      ? (value as Metodo_pagamento)
      : undefined;
  })();
  const formatFileSize = (value?: number | null) => {
    if (!value) return "Tamanho não informado";
    if (value < 1024 * 1024) return `${(value / 1024).toFixed(1)} KB`;
    return `${(value / (1024 * 1024)).toFixed(1)} MB`;
  };
  const isImageAnexo = (anexo: VendaAnexo) => String(anexo.tipo ?? "").startsWith("image/");
  const paymentMethods = (() => {
    const raw = String(venda?.forma_pagamento ?? "").trim();
    if (!raw) return [];

    if (raw.includes(":")) {
      return raw.split(/,\s+(?=[A-Z_]+:)/).map((entry) => {
        const [method, ...amountParts] = entry.split(":");
        const key = method.trim().toUpperCase();
        return {
          method: PAYMENT_METHOD_LABELS[key] ?? method.trim(),
          amount: amountParts.join(":").trim() || null,
        };
      });
    }

    return raw
      .split(",")
      .map((method) => method.trim())
      .filter(Boolean)
      .map((method) => {
        const key = method.toUpperCase();
        return {
          method: PAYMENT_METHOD_LABELS[key] ?? method,
          amount: null,
        };
      });
  })();

  // ====== DATA LOADERS
  const handleGetVenda = async (vendaId: number) => {
    setIsLoadingOs(true);
    try {
      const response = await axios.get(`/api/venda/${vendaId}`);
      if (response.status === 200) {
        setVenda(response.data.data);
      }
    } catch  {
      toast.error("Não foi possível carregar a Venda");
    } finally {
      setIsLoadingOs(false);
    }
  };

  const handleGetTransactions = async (pageNumber?: number, vendaIdArg?: number) => {
    const targetId = vendaIdArg ?? venda?.id;
    if (!targetId) return;
    setIsLoading(true);
    try {
      const response = await axios.get("/api/transaction", {
        params: {
          page: pageNumber || 1,
          limit: pagination.limit,
          vendaid: targetId,
        },
      });
      if (response.status === 200) {
        const { data } = response;
        setTransactions(data.data);
        setPagination(data.pagination);
      }
    } catch  {
      toast.error("Não foi possível carregar as transações");
    } finally {
      setIsLoading(false);
    }
  };

  const handleGetAnexos = async (vendaIdArg?: number) => {
    const targetId = vendaIdArg ?? venda?.id;
    if (!targetId) return;

    setIsLoadingAnexos(true);
    try {
      const response = await axios.get(`/api/venda/${targetId}/anexos`);
      const items = Array.isArray(response.data?.items)
        ? response.data.items.map((item: any) => ({
            id: Number(item.id),
            nome: String(item.nome ?? "Anexo"),
            tipo: item.tipo ?? null,
            tamanho:
              typeof item.tamanho === "number"
                ? item.tamanho
                : Number(item.tamanho ?? 0) || null,
            url: String(item.url ?? ""),
            categoria: (item.categoria ?? "OUTROS") as VendaAnexoCategoria,
            createdat: item.createdat ?? null,
          }))
        : [];
      setAnexos(items);
    } catch {
      toast.error("Não foi possível carregar os anexos");
    } finally {
      setIsLoadingAnexos(false);
    }
  };

  useEffect(() => {
    if (!IsOpen) {
      setTransactions([]);
      setVenda(undefined);
      setAnexos([]);
    }
  }, [IsOpen]);

  const handleDeleteTransaction = async (id: number) => {
    setIsDeleting(true);
    toast(
      <div className="flex gap-2 items-center flex-nowrap">
        <Loader className="animate-spin w-4" />
        <span className="text-nowrap">Deletando transação...</span>
      </div>,
    );
    try {
      const response = await axios.delete(`/api/transaction/${id}/os`);
      if (response.status === 204) {
        handleGetTransactions(pagination.page);
        toast.success("Transação deletada!");
      } else {
        toast.warning(`Status inesperado: ${response.status}`);
      }
    } catch (error) {
      if (isAxiosError(error)) {
        toast.error("Erro ao deletar", {
          description: error.response?.data?.error || "Tente novamente.",
        });
      } else {
        toast.error("Erro ao deletar");
      }
    } finally {
      setIsDeleting(false);
      setIsAlertOpen(false);
    }
  };

  useEffect(() => {
    if (vendaId && IsOpen) {
      handleGetVenda(vendaId);
      handleGetTransactions(undefined, vendaId);
      handleGetAnexos(vendaId);
    }
  }, [vendaId, IsOpen]);

  // ====== RENDER
  if (isLoadingOs) {
    return (
      <DialogContent className="h-dvh w-[100svw] max-w-[100svw] p-0 overflow-hidden rounded-none sm:max-w-[1100px] sm:max-h-[850px] sm:w-[95vw] sm:rounded-2xl">
        <DialogHeader className="hidden">
          <DialogTitle></DialogTitle>
        </DialogHeader>
        <div className="flex h-full min-h-0 flex-col justify-center items-center">
          <div className="size-8 border-t-2 border-primary rounded-t-full animate-spin"></div>
          <span className="text-primary">Carregando</span>
        </div>
      </DialogContent>
    );
  }

  if (!venda) return null;

  return (
    <DialogContent className="h-svh w-[100svw] max-w-[100svw] p-0 overflow-hidden rounded-none sm:max-w-[1100px] sm:max-h-[850px] sm:w-[95vw] sm:rounded-2xl">
      <div className="flex h-full min-h-0 min-w-0 flex-col">
        <DialogHeader className="shrink-0 px-6 py-4 border-b">
          <DialogTitle>
            Venda #{venda.id} <span className="text-muted-foreground text-sm font-light"> | PAGAMENTOS </span>
          </DialogTitle>
          <DialogDescription>Pagamentos da Venda</DialogDescription>
        </DialogHeader>

        {/* Barra de progresso fina no topo */}
        <div
          className={`transition-all ${
            isLoading ? "opacity-100" : "opacity-0"
          } h-0.5 bg-slate-400 w-full overflow-hidden left-0 right-0 top-0 relative`}
        >
          <div
            className={`w-1/2 bg-primary h-full absolute left-0 rounded-lg -translate-x-[100%] ${
              isLoading ? "animate-slideIn" : ""
            }`}
          />
        </div>

        <div className="h-full min-h-0 overflow-y-auto overflow-x-hidden min-w-0 dark:bg-muted-foreground/5 px-6 py-4 space-y-2">
          <div className="grid grid-cols-1 gap-2 xl:grid-cols-[minmax(0,1fr)_minmax(280px,360px)]">
            <div className="overflow-hidden rounded-lg border bg-background">
              <div className="grid gap-px bg-border sm:grid-cols-2 xl:grid-cols-4">
                <div className="bg-background p-3">
                  <span className="text-[11px] uppercase tracking-wide text-muted-foreground">Cliente</span>
                  <p className="mt-1 truncate text-sm font-medium" title={venda.cliente?.nomerazaosocial || ""}>
                    {venda.cliente?.nomerazaosocial || "-"}
                  </p>
                  <p className="truncate text-xs text-muted-foreground">
                    {venda.cliente?.telefone || venda.cliente?.email || "Sem contato"}
                  </p>
                </div>
                <div className="bg-background p-3">
                  <span className="text-[11px] uppercase tracking-wide text-muted-foreground">Venda</span>
                  <p className="mt-1 text-sm font-medium">{venda.status || "-"}</p>
                  <p className="text-xs text-muted-foreground">{formatDate(venda.datavenda)}</p>
                </div>
                <div className="bg-background p-3">
                  <span className="text-[11px] uppercase tracking-wide text-muted-foreground">Vendedor</span>
                  <p className="mt-1 truncate text-sm font-medium">{venda.criador?.nome || venda.created_by || "-"}</p>
                  <p className="text-xs text-muted-foreground">Responsavel</p>
                </div>
                <div className="bg-background p-3">
                  <span className="text-[11px] uppercase tracking-wide text-muted-foreground">Cobranca</span>
                  <p className="mt-1 text-sm font-medium">{formatarEmReal(venda.valortotal || 0)}</p>
                  <p className="text-xs text-muted-foreground">Aberto: {formatarEmReal(saldoDevedor)}</p>
                </div>
              </div>
              <div className="grid gap-px bg-border sm:grid-cols-4">
                <div className="bg-background px-3 py-2">
                  <span className="text-[11px] uppercase tracking-wide text-muted-foreground">Itens</span>
                  <p className="text-sm font-medium">
                    {venda.itens?.length ?? 0} item(ns) - {formatarEmReal(venda.sub_total || 0)}
                  </p>
                </div>
                <div className="bg-background px-3 py-2">
                  <span className="text-[11px] uppercase tracking-wide text-muted-foreground">Canal</span>
                  <p className="text-sm">{venda.canal || "-"}</p>
                </div>
                <div className="bg-background px-3 py-2">
                  <span className="text-[11px] uppercase tracking-wide text-muted-foreground">Desconto</span>
                  <p className="text-sm">
                    {venda.desconto_tipo ? `${venda.desconto_tipo} - ${formatarEmReal(venda.desconto_valor || 0)}` : "-"}
                  </p>
                </div>
                <div className="bg-background px-3 py-2">
                  <span className="text-[11px] uppercase tracking-wide text-muted-foreground">Anexos</span>
                  <p className="text-sm font-medium">{anexos.length} arquivo(s)</p>
                </div>
              </div>
            </div>

            <div className="rounded-lg border bg-background p-3">
              <div className="mb-2 flex items-center justify-between gap-2">
                <span className="text-[11px] uppercase tracking-wide text-muted-foreground">Metodos de pagamento</span>
                <Badge variant="outline">{paymentMethods.length}</Badge>
              </div>
              {paymentMethods.length > 0 ? (
                <div className="divide-y rounded-md border">
                  {paymentMethods.map((item, index) => (
                    <div key={`${item.method}-${index}`} className="flex items-center justify-between gap-3 px-3 py-2 text-sm">
                      <span className="truncate font-medium">{item.method}</span>
                      <span className="shrink-0 text-muted-foreground">{item.amount ?? "Valor nao informado"}</span>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="rounded-md border border-dashed px-3 py-5 text-center text-sm text-muted-foreground">
                  Nenhum metodo informado.
                </div>
              )}
            </div>
          </div>

          <div className="rounded-lg border bg-background px-3 py-2">
            <div className="flex items-center justify-between gap-3">
              <div className="flex min-w-0 items-center gap-2">
                <Paperclip className="h-4 w-4 text-muted-foreground" />
                <span className="text-[11px] uppercase tracking-wide text-muted-foreground">Anexos da venda</span>
                <Badge variant="secondary">{anexos.length}</Badge>
              </div>
              <button
                type="button"
                className="flex shrink-0 items-center gap-1 text-xs text-muted-foreground hover:text-foreground"
                onClick={() => handleGetAnexos(venda.id)}
              >
                Recarregar
                <Loader2 className={`h-3 w-3 ${isLoadingAnexos ? "animate-spin" : ""}`} />
              </button>
            </div>

            {isLoadingAnexos ? (
              <div className="mt-2 flex h-16 items-center justify-center gap-2 rounded-md border border-dashed text-sm text-muted-foreground">
                <div className="h-4 w-4 animate-spin rounded-full border-b-2 border-primary" />
                Carregando anexos...
              </div>
            ) : anexos.length === 0 ? (
              <div className="mt-2 rounded-md border border-dashed px-3 py-4 text-center text-sm text-muted-foreground">
                Nenhum anexo vinculado.
              </div>
            ) : (
              <div className="mt-2 grid gap-2 md:grid-cols-2 xl:grid-cols-3">
                {anexos.map((anexo) => (
                  <div key={anexo.id} className="flex min-w-0 items-center gap-2 rounded-md border bg-card p-2">
                    <div className="relative flex h-9 w-9 shrink-0 items-center justify-center overflow-hidden rounded bg-muted/50">
                      {isImageAnexo(anexo) ? (
                        <Image
                          src={anexo.url}
                          alt={anexo.nome}
                          className="object-cover"
                          fill
                          sizes="40px"
                          unoptimized
                        />
                      ) : (
                        <FileText className="h-4 w-4 text-muted-foreground" />
                      )}
                    </div>
                    <div className="min-w-0 flex-1">
                      <p className="truncate text-sm font-medium" title={anexo.nome}>
                        {anexo.nome}
                      </p>
                      <p className="truncate text-xs text-muted-foreground">
                        {getVendaAnexoCategoriaLabel(anexo.categoria)} - {formatFileSize(anexo.tamanho)}
                      </p>
                    </div>
                    <Button type="button" variant="outline" size="sm" className="h-8 shrink-0 px-2" asChild>
                      <a href={anexo.url} target="_blank" rel="noreferrer" aria-label="Abrir anexo">
                        <ExternalLink className="h-4 w-4" />
                      </a>
                    </Button>
                  </div>
                ))}
              </div>
            )}
          </div>

          {venda.observacoes_fiscais ? (
            <div className="rounded-lg border bg-background px-3 py-2">
              <span className="text-[11px] uppercase tracking-wide text-muted-foreground">Observacoes fiscais</span>
              <p className="mt-1 line-clamp-3 text-sm whitespace-pre-wrap">{venda.observacoes_fiscais}</p>
            </div>
          ) : null}
