"use client";

import { Button } from "@/components/ui/button";
import { Card,CardContent,CardHeader,CardTitle } from "@/components/ui/card";
import {
DropdownMenu,
DropdownMenuContent,
DropdownMenuItem,
DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Select,SelectContent,SelectItem,SelectTrigger,SelectValue } from "@/components/ui/select";
import { Table,TableBody,TableCell,TableHeader,TableRow } from "@/components/ui/table";
import { Tabs,TabsList,TabsTrigger } from "@/components/ui/tabs";
import formatarEmReal from "@/utils/formatarEmReal";
import { formatDate } from "@/utils/formatDate";
import {
ChevronLeftIcon,
ChevronRightIcon,
ChevronsLeft,
ChevronsRight,
DollarSign,
FileText,
Loader2,
MoreHorizontal
} from "lucide-react";
import * as React from "react";
import { useEffect,useState } from "react";
import { VendaComItens,vendaStatus } from "../../../(vendas)/historicovendas/types";
import { useConfig } from "../../../config-context";
import { EmissaoNotaDialog } from "../../../ordens/components/dialogs/emissao-nota-dialog/emissao-nota-dialog";
import {
PaymentListFilters,
PaymentsFilterSheet,
} from "../../components/payments-filter-sheet";
import { Pagination } from "../../fluxodecaixa/types";
import VendasFinancialDialog from "./vendasFinancialDialog/vendasFinancialDialog";

interface OsTableProps {
  vendas: VendaComItens[];
  pagination: Pagination;
  handleGetVendas: (
    status: vendaStatus,
    pageNumber?: number,
    limit?: number,
    search?: string,
    filters?: PaymentListFilters,
  ) => void;
  isLoading: boolean;
  search: string;
}

export default function VendasTable({ vendas, pagination, handleGetVendas, isLoading, search }: OsTableProps) {
  // ID estável para o Select de "itens por página"
  const [selectedStatus, setSelectedStatus] = useState<vendaStatus>(vendaStatus.PAGAMENTO);
  const [open, setOpen] = useState(false);
  const [openEmissao, setOpenEmissao] = useState(false);
  const [emissaoId, setEmissaoId] = useState<number | undefined>(undefined);
  const [filtersOpen, setFiltersOpen] = useState(false);
  const [filters, setFilters] = useState<PaymentListFilters>({
    cliente: "",
    notaNumero: "",
  });
  const limitUid = React.useId();
  const limitListboxId = `${limitUid}-os-limit-listbox`;
  const tabTheme =
    " dark:data-[state=active]:bg-primary data-[state=active]:bg-primary data-[state=active]:text-primary-foreground";
  const hasActiveFilters = Boolean(
    filters.cliente.trim() ||
      filters.notaNumero.trim() ||
      filters.dataInicio ||
      filters.dataFim,
  );

  useEffect(() => {
    handleGetVendas(selectedStatus, 1, pagination.limit, search, filters);
  }, [selectedStatus]);
  const config = useConfig();

  return (
    <Card className="">
      <CardHeader className="border-b-2 flex flex-col">
        <div className="flex flex-row justify-between gap-3 w-full">
          <CardTitle className="text-lg font-medium">
            Vendas <span className="text-muted-foreground text-xs font-mono font-extralight">|EM PAGAMENTO</span>
          </CardTitle>
          <div className="flex items-center gap-2">
            {hasActiveFilters && (
              <Button
                variant="ghost"
                size="sm"
                className="hover:cursor-pointer"
                onClick={() => {
                  const cleared = { cliente: "", notaNumero: "" };
                  setFilters(cleared);
                  handleGetVendas(selectedStatus, 1, pagination.limit, search, cleared);
                }}
              >
                Limpar filtros
              </Button>
            )}
            <PaymentsFilterSheet
              open={filtersOpen}
              onOpenChange={setFiltersOpen}
              filters={filters}
              onFiltersChange={setFilters}
              onAplicar={() =>
                handleGetVendas(selectedStatus, 1, pagination.limit, search, filters)
              }
              onLimpar={() => {
                const cleared = { cliente: "", notaNumero: "" };
                setFilters(cleared);
                handleGetVendas(selectedStatus, 1, pagination.limit, search, cleared);
              }}
            />
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div
            onClick={() =>
              handleGetVendas(selectedStatus, pagination.page, pagination.limit, search, filters)
            }
            className="flex flex-row space-x-1 items-center hover:cursor-pointer"
          >
            <Loader2 className="w-3 h-3" />
            <span className="text-xs text-muted-foreground"> Recarregar</span>
          </div>
          {hasActiveFilters && (
            <span className="text-xs text-muted-foreground">Filtros ativos</span>
          )}
        </div>
        <Tabs defaultValue="abertas" className="w-full items-center">
          <TabsList className="rounded-b-none">
            <TabsTrigger
              onClick={() => setSelectedStatus(vendaStatus.PAGAMENTO)}
              className={" rounded-b-none cursor-pointer" + tabTheme}
              value="abertas"
            >
              Abertas
            </TabsTrigger>
            <TabsTrigger
              onClick={() => setSelectedStatus(vendaStatus.FINALIZADA)}
              className={" rounded-b-none cursor-pointer" + tabTheme}
              value="concluidas"
            >
              Concluídas
            </TabsTrigger>
          </TabsList>
        </Tabs>
      </CardHeader>

      <CardContent className="min-h-[300px] -mt-[24px] px-4 pb-4 pt-0 relative flex flex-col justify-between">
        {/* barra superior de loading */}
        <div
          className={`${isLoading && "opacity-100"
            } transition-all opacity-0 h-0.5 bg-slate-400 w-full overflow-hidden absolute left-0 right-0 top-0`}
        >
          <div
            className={`w-1/2 bg-primary h-full absolute left-0 rounded-lg -translate-x-[100%] ${isLoading && "animate-slideIn "
              }`}
          />
        </div>
        <EmissaoNotaDialog
          onOpenChange={setOpenEmissao}
          open={openEmissao}
          vendaId={emissaoId}
        />
        <Table className="text-xs mt-6">
          <TableHeader>
            <TableRow className="font-bold">
              <TableCell>ID</TableCell>
              <TableCell>Nota</TableCell>
              <TableCell>Cliente</TableCell>
              <TableCell>Data</TableCell>
              <TableCell>Valor Total</TableCell>
              <TableCell>Status</TableCell>
              <TableCell></TableCell>
            </TableRow>
          </TableHeader>

          <TableBody>
            {vendas.length > 0 ? (
              vendas.map((v) => {
                // IDs estáveis por linha para o menu
                const triggerId = `os-row-${v.id}-menu-btn`;
                const menuId = `os-row-${v.id}-menu`;

                return (
                  <TableRow key={v.id} className="hover:cursor-pointer">
                    {/* ... suas outras células (descrição, data etc.) aqui, se/quando tiver ... */}
                    <TableCell>{v.id}</TableCell>
                    <TableCell>{v.notaNumero ?? "-"}</TableCell>
                    <TableCell>{v.cliente.nomerazaosocial}</TableCell>
                    <TableCell>{formatDate(v.datavenda)}</TableCell>
                    <TableCell>{formatarEmReal(v.valortotal)}</TableCell>
                    <TableCell>{v.status}</TableCell>

                    <TableCell className="flex justify-end">
                      <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                          <Button
                            id={triggerId}
                            aria-controls={menuId}
                            variant="ghost"
                            className="h-8 w-8 p-0 cursor-pointer"
                          >
                            <MoreHorizontal className="h-4 w-4" />
                          </Button>
                        </DropdownMenuTrigger>

                        <DropdownMenuContent id={menuId} aria-labelledby={triggerId} className="space-y-1">
                          <VendasFinancialDialog
                            handleGetVendas={handleGetVendas}
                            open={open}
                            onOpenChange={setOpen}
                            vendaId={v.id}
                          >
                            <DropdownMenuItem onSelect={(e) => e.preventDefault()}>
                              <DollarSign className="h-4 w-4" />
                              <span>Pagamento</span>
                            </DropdownMenuItem>
                          </VendasFinancialDialog>
                          {
                            config?.habilitar_emissao_nfe &&
                            (config?.emissao_nf_vendas_nao_pagas ? v.status === "PAGAMENTO" ||
                              v.status === "FINALIZADA" : v.status === "FINALIZADA") && (
                              <DropdownMenuItem
                                onClick={() => {
                                  setEmissaoId(v.id);
                                  setOpenEmissao(true);
                                }}
                              >
                                <FileText className="h-4 w-4" />
                                <span>Emitir NF</span>
                              </DropdownMenuItem>
                            )
                          }
                        </DropdownMenuContent>
                      </DropdownMenu>
                    </TableCell>
                  </TableRow>
                );
              })
            ) : (
              <TableRow>
                <TableCell className="text-center h-20" colSpan={99}>
                  Não existem vendas com este status
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>

        <div className="flex items-center mt-4 justify-between">
          <div className="text-xs text-muted-foreground mr-2 flex flex-nowrap">
            <span>{pagination.limit * (pagination.page - 1) + 1}</span>
            {" - "}
            <span>{pagination.limit * (pagination.page - 1) + vendas.length}</span>
          </div>

          <div className="flex items-center justify-center space-x-2">
            <Button
              variant="outline"
              size="icon"
              className="hover:cursor-pointer"
              onClick={() => handleGetVendas(selectedStatus, 1, pagination.limit, search, filters)}
              disabled={pagination.page === 1}
            >
              <ChevronsLeft className="h-4 w-4" />
            </Button>

            <Button
              variant="outline"
              size="icon"
              className="hover:cursor-pointer"
              onClick={() => handleGetVendas(selectedStatus, pagination.page - 1, pagination.limit, search, filters)}
              disabled={pagination.page === 1}
            >
              <ChevronLeftIcon className="h-4 w-4" />
            </Button>

            <span className="text-xs font-medium text-nowrap">
              Pg. {pagination.page} de {pagination.totalPages || 1}
            </span>

            <Button
              className="hover:cursor-pointer"
              variant="outline"
              size="icon"
              onClick={() => handleGetVendas(selectedStatus, pagination.page + 1, pagination.limit, search, filters)}
              disabled={pagination.page === pagination.totalPages || pagination.totalPages === 0}
            >
              <ChevronRightIcon className="h-4 w-4" />
            </Button>

            <Button
              className="hover:cursor-pointer"
              variant="outline"
              size="icon"
              onClick={() => handleGetVendas(selectedStatus, pagination.totalPages, pagination.limit, search, filters)}
              disabled={pagination.page === pagination.totalPages || pagination.totalPages === 0}
            >
              <ChevronsRight className="h-4 w-4" />
            </Button>
          </div>

          {/* Select de itens por página com IDs estáveis */}
          <div>
            <Select>
              <SelectTrigger className="hover:cursor-pointer ml-2" aria-controls={limitListboxId}>
                <SelectValue placeholder={`${pagination.limit}`} />
              </SelectTrigger>
              <SelectContent id={limitListboxId}>
                <SelectItem className="hover:cursor-pointer" value="20">
                  {pagination.limit}
                </SelectItem>
                {/* adicione mais opções se desejar (10/20/50/100...) */}
              </SelectContent>
            </Select>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

"use client"
import { useEffect, useState } from "react";
import axios from "axios";
import { VendaComItens, vendaStatus } from "../../(vendas)/historicovendas/types";
import VendasTable from "./components/vendasTable";
import { PaymentListFilters } from "../components/payments-filter-sheet";

export default function AssistentePagamentoVendas (){
    const [vendas, setVendas] = useState<VendaComItens[]>([])
    const [pagination, setPagination] = useState({
    total: 0,
    page: 1,
    limit: 20,
    totalPages: 0,
  });
    const [isLoading, setIsLoading] = useState(false)
    const[search, ] = useState("")
    

    const handleGetVendas = async (
      status: vendaStatus,
      pageNumber?: number,
      limit?: number,
      search?: string,
      filters?: PaymentListFilters,
    ) => {
    setIsLoading(true);
    try {
      const response = await axios.get("/api/venda", {
        params: {
          page: pageNumber || 1,
          limit: limit || pagination.limit,
          q: search || "",
          status: status,
          cliente: filters?.cliente || "",
          notaNumero: filters?.notaNumero || "",
          dateFrom: filters?.dataInicio
            ? filters.dataInicio.toISOString().slice(0, 10)
            : "",
          dateTo: filters?.dataFim
            ? filters.dataFim.toISOString().slice(0, 10)
            : "",
        },
      });
      if (response.status === 200) {
        const { data } = response;
        setVendas(data.data);
        setPagination({...pagination, limit:data.pagination.limit, page: data.pagination.page, totalPages:data.pagination.totalPages, total: data.pagination.total});
      }
    } catch {
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(()=> {
    handleGetVendas(vendaStatus.PAGAMENTO);
  },[])

    return (

    <div className="p-y-4 space-y-4">
        <VendasTable
        search={search}
        isLoading={isLoading}
        handleGetVendas={handleGetVendas}
        vendas={vendas}
        pagination={pagination}
        />
    </div>

    )
}

"use client";
"use cliente";
import axios from "axios";
import { useEffect,useState } from "react";
import { PaymentListFilters } from "../../(financeiro)/components/payments-filter-sheet";
import Cards from "./components/cards";
import VendasDataTable from "./components/vendas-data-table";
import {
Pagination,
VendaComItens,
vendaStatus,
VendaStatusMetricsData,
} from "./types";

function formatMonthFromDate(date: Date): string {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0"); // 0-11 -> 1-12
  return `${year}-${month}`;
}
export default function HistoricoVendas() {
  const [loadingStatusCounter, setLoadingStatusCounter] = useState(false);
  const [status] = useState<vendaStatus | "TODOS">("TODOS");

  const totalVendas = 0;
  const [data, setData] = useState<VendaStatusMetricsData | null>(null);
  const [vendas, setVendas] = useState<VendaComItens[]>([]);
  const date = new Date(); // hoje
  const month = formatMonthFromDate(date);
  const [isLoading, setIsLoading] = useState(false);
  const [isOpen, setIsOpen] = useState(false);
  const [selectedVendaId, setSelectedVendaId] = useState<number | undefined>(
    undefined
  );
  const [pagination, setPagination] = useState<Pagination>({
    total: 0,
    page: 1,
    limit: 20,
    totalPages: 0,
  });
  const [search] = useState("");
  const [filters, setFilters] = useState<PaymentListFilters>({
    cliente: "",
    notaNumero: "",
  });

  const handleGetVendas = async (
    pageNumber?: number,
    limit?: number,
    searchText?: string,
    statusValue?: vendaStatus | "TODOS",
    listFilters?: PaymentListFilters,
  ) => {
    setIsLoading(true);
    try {
      const activeFilters = listFilters ?? filters;
      const response = await axios.get("/api/venda", {
        params: {
          page: pageNumber || 1,
          limit: pagination.limit,
          search: searchText || undefined,
          status: statusValue || "TODOS",
          cliente: activeFilters.cliente || "",
          notaNumero: activeFilters.notaNumero || "",
          dateFrom: activeFilters.dataInicio
            ? activeFilters.dataInicio.toISOString().slice(0, 10)
            : "",
          dateTo: activeFilters.dataFim
            ? activeFilters.dataFim.toISOString().slice(0, 10)
            : "",
        },
      });
      if (response.status === 200) {
        const { data } = response;
        setVendas(data.data);
        setPagination(data.pagination);
      }
    } catch  {
    } finally {
      setIsLoading(false);
    }
  };

  async function fetchMetrics() {
    try {
      setLoadingStatusCounter(true);

      const url = month
        ? `/api/venda/status-counter?month=${month}`
        : `/api/venda/status-counter`;

      const res = await axios.get(url);

      setData(res.data.data); // o payload vem como {data: {...}}
    } catch  {
    } finally {
      setLoadingStatusCounter(false);
    }
  }

  useEffect(() => {
    handleGetVendas(1, pagination.limit, search, status);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);
  useEffect(() => {
    fetchMetrics();
  }, [, month]);

  return (
    <div className="mx-auto space-y-6">
      <Cards
        loadingStatusCounter={loadingStatusCounter}
        totalVendas={totalVendas}
        statusCounts={data}
      />
      <VendasDataTable
        filters={filters}
        setFilters={setFilters}
        handleGetVendas={handleGetVendas}
        isLoading={isLoading}
        isOpen={isOpen}
        setIsOpen={setIsOpen}
        fetchStatusCounts={fetchMetrics}
        pagination={pagination}
        search={search}
        selectedVendaId={selectedVendaId}
        setSelectedVendaId={setSelectedVendaId}
        status={status}
        vendas={vendas}
      />
    </div>
  );
}

