import { Select,SelectContent,SelectItem,SelectTrigger,SelectValue } from "@/components/ui/select";
import { Separator } from "@/components/ui/separator";
import { Table,TableBody,TableCell,TableHead,TableHeader,TableRow } from "@/components/ui/table";
import { Tabs,TabsContent,TabsList,TabsTrigger } from "@/components/ui/tabs";
import { Tooltip,TooltipContent,TooltipTrigger } from "@/components/ui/tooltip";
import { cn } from "@/lib/utils";
import axios,{ isAxiosError } from "axios";
import {
ArrowLeftRight,
Building2,
Camera,
Car,
Check,
ChevronDown,
ChevronsUpDown,
ClipboardList,
Ellipsis,
FileText,
IdCard,
Loader2,
Mail,
MapPin,
Pen,
Phone,
Plus,
Search,
User
} from "lucide-react";
import { Fragment,useEffect,useState } from "react";
import { toast } from "sonner";
import { VeiculoDialog } from "../../../veiculos/dialgo-veiculo/dialog-veiculo";
import { Cliente_rank,Customer } from "../../types";
import { ESTADOS_BRASIL,StatusCliente,TipoPessoa } from "./types";
import { formatCep,formatCpfCnpj,formatTelefone,getRankEmoji } from "./utils";

interface EditContentProps {
  customerId: number;
  isDesktop?: boolean;
  onUpdate?: (c: Customer) => void;
}

const statusOptionClass: Record<StatusCliente, string> = {
  ATIVO:
    "bg-emerald-100 text-emerald-800 focus:bg-emerald-100 focus:text-emerald-800 dark:bg-emerald-950/50 dark:text-emerald-300 dark:focus:bg-emerald-950/50 dark:focus:text-emerald-300",
  INATIVO:
    "bg-slate-100 text-slate-800 focus:bg-slate-100 focus:text-slate-800 dark:bg-slate-900 dark:text-slate-300 dark:focus:bg-slate-900 dark:focus:text-slate-300",
  PENDENTE:
    "bg-amber-100 text-amber-800 focus:bg-amber-100 focus:text-amber-800 dark:bg-amber-950/50 dark:text-amber-300 dark:focus:bg-amber-950/50 dark:focus:text-amber-300",
};

const statusLabel: Record<StatusCliente, string> = {
  ATIVO: "Ativo",
  INATIVO: "Inativo",
  PENDENTE: "Pendente",
};

const formatCurrency = (value: number) => {
  return new Intl.NumberFormat("pt-BR", {
    style: "currency",
    currency: "BRL",
  }).format(value || 0);
};

const formatDate = (date: string | Date | null | undefined) => {
  if (!date) return "-";
  return new Intl.DateTimeFormat("pt-BR", {
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
  }).format(new Date(date));
};

const getStatusBadge = (status?: string | null) => {
  if (!status) return <Badge variant="outline">Desconhecido</Badge>;
  const upper = status.toUpperCase();
  const formatted = status.charAt(0).toUpperCase() + status.slice(1).toLowerCase().replace(/_/g, " ");

  switch (upper) {
    case "ORCAMENTO":
      return <Badge variant="outline" className="border-violet-500/20 bg-violet-500/10 text-violet-700 dark:text-violet-400">Orçamento</Badge>;
    case "ABERTA":
    case "EM_ANDAMENTO":
      return <Badge variant="outline" className="border-blue-500/20 bg-blue-500/10 text-blue-700 dark:text-blue-400">Aberta</Badge>;
    case "PENDENTE":
    case "APROVACAO_ORCAMENTO":
      return <Badge variant="outline" className="border-amber-500/20 bg-amber-500/10 text-amber-700 dark:text-amber-400">Pendente</Badge>;
    case "CONCLUIDO":
    case "FINALIZADA":
      return <Badge variant="outline" className="border-emerald-500/20 bg-emerald-500/10 text-emerald-700 dark:text-emerald-400">Finalizada</Badge>;
    case "CANCELADA":
      return <Badge variant="outline" className="border-red-500/20 bg-red-500/10 text-red-700 dark:text-red-400">Cancelada</Badge>;
    case "PAGAMENTO":
      return <Badge variant="outline" className="border-cyan-500/20 bg-cyan-500/10 text-cyan-700 dark:text-cyan-400">Pagamento</Badge>;
    default:
      return <Badge variant="outline">{formatted}</Badge>;
  }
};

export default function EditContent({ customerId, isDesktop = true, onUpdate }: EditContentProps) {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isLoadingCNPJ, setIsLoadingCNPJ] = useState(false);
  const [selectedCustomer, setselectedCustomer] = useState<Customer | undefined>(undefined);
  const [isLoading, setIsLoading] = useState(true);
  const [isLoadingCep, setIsLoadingCep] = useState(false);
  const { cidades, loading } = useGetCidades(selectedCustomer?.estado ?? undefined);
  const [open, setOpen] = useState(false);
  const [open2, setOpen2] = useState(false);
  const [openVehicle, setOpenVehicle] = useState(false);
  const [veiculoId, setSelectedVeiculoId] = useState<number | undefined>(undefined);
  const [isLoadingVeiculos, setIsLoadingVeiculos] = useState(false);
  const [openCustomerSelect, setOpenCustomerSelect] = useState(false);
  const [veiculoTransferId, setVeiculoTransferId] = useState<number | undefined>(undefined);
  const [transferindo, setTransferindo] = useState(false);
  const [expandedOrdemId, setExpandedOrdemId] = useState<number | null>(null);

  function validarEmailDigitado(email: string): boolean {
    const valor = email.trim();
    if (!valor) return true;

    // Mesmo regex usado na constraint (case-insensitive)
    const regex = /^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}$/i;

    return regex.test(valor);
  }

  const handleInputChange = (field: keyof Customer, value: string) => {
    if (selectedCustomer) {
      setselectedCustomer({ ...selectedCustomer, [field]: value });
    }
  };

  const handleGetCustomer = async (customerId: number, notifyUpdate = false) => {
    setIsLoading(true);
    try {
      const response = await axios.get("/api/customers/" + customerId);

      if (response.status === 200) {
        // console.log(response)
        const { data } = response;
        setselectedCustomer(data.data);
        if (notifyUpdate) onUpdate?.(data.data);
      }
    } catch (error) {
      console.log("Erro ao buscar cliente:", error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleGetCNPJ = async () => {
    if (selectedCustomer?.cpfcnpj && selectedCustomer?.cpfcnpj?.length < 14) {
      toast.warning("CPF inválido para consulta de CNPJ");
      return;
    }
    setIsLoadingCNPJ(true);
    try {
      const response = await axios.get(`https://publica.cnpj.ws/cnpj/${selectedCustomer?.cpfcnpj}`);
      if (response.status === 200) {
        console.log(response.data);
        const juridica = response.data;
        setselectedCustomer((prev) => {
          if (!prev) return undefined;
          return {
            ...prev,
            nomerazaosocial: juridica.razao_social,
            cep: juridica.estabelecimento.cep,
            email: juridica.estabelecimento.email,
            endereconumero: juridica.estabelecimento.numero,
            telefone: `${juridica.estabelecimento.ddd1}${juridica.estabelecimento.telefone1}`,
            estado: juridica.estabelecimento.estado.sigla,
            cidade: juridica.estabelecimento.cidade.nome,
            codigomunicipio: String(juridica.estabelecimento.cidade.codigo_ibge),
            endereco: juridica.estabelecimento.logradouro,
            enderecocomplemento: juridica.estabelecimento.complemento,
            bairro: juridica.estabelecimento.bairro,
          };
        });
      }
    } catch (error) {
      if (isAxiosError(error)) {
        if (error.status === 429) {
          toast.error("Muitas tentativas", {
            description: "Aguarde um pouco e tente novamente",
          });
        }
        if (error.status === 400) {
          toast.error("CNPJ não encontrado", {
            description: "Verifique o dado informado",
          });
        }
        if (error.status === 404) {
          toast.error("Erro no servidor de consulta", {
            description: "Verifique com o administrador",
          });
        }
      }
    } finally {
      setIsLoadingCNPJ(false);
    }
  };

  const handleGetCep = async () => {
    if (!selectedCustomer?.cep) {
      toast.error("Informe um CEP para buscar");
      return;
    }
    setIsLoadingCep(true);
    try {
      const response = await axios.get(`https://opencep.com/v1/${selectedCustomer?.cep}`);
      if (response.status === 200) {
        console.log(response);
        const enderecoResponse = response.data;
        if (selectedCustomer) {
          setselectedCustomer({
            ...selectedCustomer,
            endereco: enderecoResponse.logradouro,
            cidade: enderecoResponse.localidade,
            codigomunicipio: enderecoResponse.ibge,
            estado: enderecoResponse.uf,
            bairro: enderecoResponse.bairro,
          });
        }
      }
    } catch (error) {
      if (isAxiosError(error)) {
        if (error.status === 404) {
          toast.error("CEP não encontrado.");
        }
      }
    } finally {
      setIsLoadingCep(false);
    }
  };

  const handleUpdateCustomer = async () => {
    if (!validarEmailDigitado(selectedCustomer?.email || "")) {
      toast.warning("Insira um email válido");
      return;
    }
    setIsSubmitting(true);
    try {
      const response = await axios.put("/api/customers/" + customerId, selectedCustomer);

      if (response.status === 200) {
        // console.log(response)
        const { data } = response;
        setselectedCustomer(data.data);
        console.log("Cliente atualizado:", data.data);
        toast.success("Cliente Atualizado");
        await handleGetCustomer(data.data.id, true);
      }
    } catch (error) {
      console.log("Erro ao atualizar cliente:", error);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleGetClienteVeiculos = async () => {
    setIsLoadingVeiculos(true);
    try {
      const response = await axios.get(`/api/veiculos/cliente/${selectedCustomer?.id}`);
      if (response.status === 200 && selectedCustomer) {
        const updatedCustomer = {
          ...selectedCustomer,
          veiculos: response.data.veiculos,
        };
        setselectedCustomer(updatedCustomer);
        onUpdate?.(updatedCustomer);
      }
    } catch (error) {
      if (isAxiosError(error)) {
        toast("Erro:", { description: error.response?.data.error });
      }
    } finally {
      setIsLoadingVeiculos(false);
    }
  };

  const handleVehicleTransfer = async (novoDonoId: number) => {
    toast(
      <div className="flex felx-row gap-1 items-center">
        <Loader2 className="w-3 h-3 animate-spin" />
        <span>Transferindo veículo...</span>{" "}
      </div>,
    );
    setTransferindo(true);
    try {
      const response = await axios.post(`/api/veiculos/${veiculoTransferId}/transferencia`, {
        novoDonoId: novoDonoId,
      });
      if (response.status === 200) {
        toast.success("Veículo transferido com sucesso!");
        handleGetClienteVeiculos();
      }
    } catch (error) {
      if (isAxiosError(error)) {
        toast.error("Erro ao transferir veículo", {
          description: error.response?.data.error,
        });
      }
    } finally {
      setTransferindo(false);
    }
  };

  useEffect(() => {
    if (customerId) {
      handleGetCustomer(customerId);
    }
  }, []);

  useEffect(() => {
    console.log(selectedCustomer);
  }, [selectedCustomer]);

  const DialogShellContent = isDesktop ? DialogContent : DrawerContent;
  const DialogShellHeader = isDesktop ? DialogHeader : DrawerHeader;
  const DialogShellFooter = isDesktop ? DialogFooter : DrawerFooter;
  const DialogShellTitle = isDesktop ? DialogTitle : DrawerTitle;
  const DialogShellDescription = isDesktop ? DialogDescription : DrawerDescription;
  const DialogShellClose = isDesktop ? DialogClose : DrawerClose;

  if (isLoading) {
    return (
      <DialogShellContent
        className={
          isDesktop
            ? `
        h-svh w-[100dvw] max-w-[100dvw] p-0 overflow-hidden min-w-0
        sm:max-w-[1100px] sm:max-h-[850px] sm:w-[95vw] sm:min-w-0
      `
            : `h-[100dvh] w-screen max-w-none min-h-dvh mt-0 rounded-none max-h-none flex flex-col`
        }
      >
        <DialogShellHeader className="hidden">
          <DialogShellTitle></DialogShellTitle>
        </DialogShellHeader>
        <div className="flex h-full min-h-0 flex-col justify-center items-center">
          <div className="size-8 border-t-2 border-primary rounded-t-full animate-spin"></div>
          <span className="text-primary">Carregando</span>
        </div>
      </DialogShellContent>
    );
  }

  if (selectedCustomer) {
    return (
      <DialogShellContent
        className={
          isDesktop
            ? `
        h-svh w-[100dvw] max-w-[100dvw] p-0 overflow-hidden min-w-0
        sm:max-w-[1100px] sm:max-h-[850px] sm:w-[95vw] sm:min-w-0
      `
            : `h-[100dvh] w-screen max-w-none min-h-dvh mt-0 rounded-none max-h-none flex flex-col`
        }
      >
        <VeiculoDialog
          setSelectedVeiculoId={setSelectedVeiculoId}
          isOpen={openVehicle}
          setIsOpen={setOpenVehicle}
          clienteId={selectedCustomer.id}
          veiculoId={veiculoId}
          onRegister={() => handleGetClienteVeiculos()}
        />
        <div className="flex h-full min-h-0 flex-col">
          <DialogShellHeader className="shrink-0 border-b px-4 py-3 sm:px-6">
            <DialogShellTitle className="flex flex-row items-center gap-2 text-sm sm:text-lg">
              Cliente #{selectedCustomer.id}
              <span className="text-muted-foreground text-sm font-light">| Edição </span>
              <Select
                value={selectedCustomer.rank || ""}
                onValueChange={(value) =>
                  setselectedCustomer({
                    ...selectedCustomer,
                    rank: value as Cliente_rank,
                  })
                }
              >
                <SelectTrigger className="bg-transparent border-none shadow-none focus:ring-0 focus:ring-offset-0 text-[10px] hover:cursor-pointer">
                  <SelectValue placeholder="Não ranqueado" />
                </SelectTrigger>
                <SelectContent align="end" className="text-xs w-min bg-none">
                  {Object.values(Cliente_rank).map((rank) => (
                    <SelectItem
                      className="hover:cursor-pointer text-[10px] text-center flex flex-row items-center"
                      value={rank}
                      key={rank}
                    >
                      {getRankEmoji(rank)}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </DialogShellTitle>
            <DialogShellDescription>Modifique dados para atualizar o cliente</DialogShellDescription>
          </DialogShellHeader>

          {/* Área principal com abas */}
          <Tabs defaultValue="Geral" className="flex-1 min-h-0 overflow-hidden pb-0">
            <div className="sticky top-0 z-10 mt-4 shrink-0">
              <div className="overflow-x-auto px-2 pb-2">
                <TabsList className="h-auto min-w-full justify-start gap-1.5 rounded-2xl border bg-muted/40 p-1 backdrop-blur-sm">
                  <TabsTrigger
                    value="Geral"
                    className="group h-8 rounded-xl border border-transparent px-3 text-xs font-medium text-muted-foreground transition-all hover:cursor-pointer hover:text-foreground data-[state=active]:bg-primary dark:data-[state=active]:bg-primary data-[state=active]:text-primary-foreground dark:data-[state=active]:text-primary-foreground data-[state=active]:shadow-sm"
                  >
                    <span className="flex items-center gap-2">
                      <User className="h-3.5 w-3.5 transition-transform group-data-[state=active]:scale-105" />
                      Geral
                    </span>
                  </TabsTrigger>
                  <TabsTrigger
                    value="Veículos"
                    className="group h-8 rounded-xl border border-transparent px-3 text-xs font-medium text-muted-foreground transition-all hover:cursor-pointer hover:text-foreground data-[state=active]:bg-primary dark:data-[state=active]:bg-primary data-[state=active]:text-primary-foreground dark:data-[state=active]:text-primary-foreground data-[state=active]:shadow-sm"
                  >
                    <span className="flex items-center gap-2">
                      <Car className="h-3.5 w-3.5 transition-transform group-data-[state=active]:scale-105" />
                      Veículos
                    </span>
                  </TabsTrigger>
                  <TabsTrigger
                    value="Ordens"
                    className="group h-8 rounded-xl border border-transparent px-3 text-xs font-medium text-muted-foreground transition-all hover:cursor-pointer hover:text-foreground data-[state=active]:bg-primary dark:data-[state=active]:bg-primary data-[state=active]:text-primary-foreground dark:data-[state=active]:text-primary-foreground data-[state=active]:shadow-sm"
                  >
                    <span className="flex items-center gap-2">
                      <ClipboardList className="h-3.5 w-3.5 transition-transform group-data-[state=active]:scale-105" />
                      Ordens de Serviço
                    </span>
                  </TabsTrigger>
                </TabsList>
              </div>
            </div>

            {/* CONTEÚDO DA ABA: o scroll fica no wrapper interno */}
            <TabsContent value="Geral" className="h-full min-h-0 overflow-hidden p-0 b">
              <div className="h-full min-h-0 overflow-auto bg-muted-foreground/5 px-4 py-4 space-y-6 sm:px-6">
                <div className="rounded-lg border bg-card p-4">
                  <div className="flex flex-col gap-4 sm:flex-row sm:items-center">
                    <div className="flex items-center gap-3">
                      <div className="relative shrink-0">
                        <Avatar className="h-12 w-12 sm:h-14 sm:w-14">
                          <AvatarImage
                            // src={fotoPreview || "/placeholder.svg"}
                            alt="Foto do cliente"
                          />
                          <AvatarFallback className="text-sm">
                            {selectedCustomer.tipopessoa === "FISICA" ? (
                              <User className="h-5 w-5 sm:h-6 sm:w-6" />
                            ) : (
                              <Building2 className="h-5 w-5 sm:h-6 sm:w-6" />
                            )}
                          </AvatarFallback>
                        </Avatar>
                        <Label htmlFor="foto-upload" className="absolute -bottom-1 -right-1 cursor-pointer">
                          <div className="rounded-full bg-primary p-1.5 text-primary-foreground transition-colors hover:bg-primary/90">
                            <Camera className="h-3 w-3" />
                          </div>
                          <input id="foto-upload" type="file" accept="image/*" className="hidden" />
                        </Label>
                      </div>
                      <div className="space-y-1">
                        <p className="text-sm font-semibold">
                          {selectedCustomer.nomerazaosocial?.trim() || `Cliente #${selectedCustomer.id}`}
                        </p>
                        <p className="text-xs text-muted-foreground">Atualize os dados cadastrais do cliente.</p>
                      </div>
                    </div>

                    <div className="grid flex-1 grid-cols-2 gap-3">
                      <div className="space-y-2">
                        <Label htmlFor="status" className="text-sm">
                          Status
                        </Label>
                        <Select
                          value={selectedCustomer.status}
                          onValueChange={(value: StatusCliente) => handleInputChange("status", value)}
                        >
                          <SelectTrigger className={cn("h-10 sm:h-11", statusOptionClass[selectedCustomer.status])}>
                            <SelectValue />
                          </SelectTrigger>
                          <SelectContent>
                            <SelectItem
                              value="ATIVO"
                              className={cn("px-2 py-1.5 text-sm font-medium hover:cursor-pointer", statusOptionClass.ATIVO)}
                            >
                              {statusLabel.ATIVO}
                            </SelectItem>
                            <SelectItem
                              value="INATIVO"
                              className={cn("px-2 py-1.5 text-sm font-medium hover:cursor-pointer", statusOptionClass.INATIVO)}
                            >
                              {statusLabel.INATIVO}
                            </SelectItem>
                            <SelectItem
                              value="PENDENTE"
                              className={cn("px-2 py-1.5 text-sm font-medium hover:cursor-pointer", statusOptionClass.PENDENTE)}
                            >
                              {statusLabel.PENDENTE}
                            </SelectItem>
                          </SelectContent>
                        </Select>
                      </div>
                      <div className="space-y-2">
                        <Label htmlFor="tipopessoa" className="text-sm">
                          Tipo de Pessoa *
                        </Label>
                        <Select
                          value={selectedCustomer.tipopessoa}
                          onValueChange={(value: TipoPessoa) => handleInputChange("tipopessoa", value)}
                        >
                          <SelectTrigger className="h-10 sm:h-11">
                            <SelectValue />
                          </SelectTrigger>
                          <SelectContent>
                            <SelectItem value="FISICA" className="hover:cursor-pointer">
                              <div className="flex items-center gap-2">
                                <User className="h-4 w-4" />
                                <span className="text-sm">Pessoa Física</span>
                              </div>
                            </SelectItem>
                            <SelectItem value="JURIDICA" className="hover:cursor-pointer">
                              <div className="flex items-center gap-2">
                                <Building2 className="h-4 w-4" />
                                <span className="text-sm">Pessoa Jurídica</span>
                              </div>
                            </SelectItem>
                          </SelectContent>
                        </Select>
                      </div>
                    </div>
                  </div>
                </div>

                {/* Dados Principais */}
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 sm:gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="cpfcnpj" className="text-sm">
                      {selectedCustomer.tipopessoa === "FISICA" ? "CPF" : "CNPJ"} *
                    </Label>
                    <div className=" relative">
                      {isLoadingCNPJ && (
                        <Loader2 className="w-4 h-4 absolute right-9 top-2.5 animate-spin text-primary" />
                      )}
                      <div className="relative">
                        <Tooltip>
                          <TooltipTrigger asChild>
                            <div
                              onClick={handleGetCNPJ}
                              className="p-1 hover:bg-gray-500/20 cursor-pointer transition-all rounded-3xl absolute top-1.5 right-2 m-0"
                            >
                              <IdCard className="w-4 h-4" />
                            </div>
                          </TooltipTrigger>
                          <TooltipContent>Consultar CNPJ</TooltipContent>
                        </Tooltip>
                        <Input
                          id="cpfcnpj"
                          inputMode="numeric"
                          className=""
                          value={formatCpfCnpj(selectedCustomer.cpfcnpj, selectedCustomer.tipopessoa) || ""}
                          onChange={(e) => {
                            const onlyNumbers = e.target.value.replace(/\D/g, "");

                            handleInputChange("cpfcnpj", onlyNumbers);
                          }}
                          placeholder={
                            selectedCustomer.tipopessoa === "FISICA" ? "000.000.000-00" : "00.000.000/0000-00"
                          }
                          maxLength={selectedCustomer.tipopessoa === "FISICA" ? 14 : 18}
                        />
                      </div>
                    </div>
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="nomerazaosocial" className="text-sm">
                      {selectedCustomer.tipopessoa === "FISICA" ? "Nome Completo" : "Razão Social"} *
                    </Label>
                    <Input
                      id="nomerazaosocial"
                      className=""
                      value={selectedCustomer.nomerazaosocial || ""}
                      onChange={(e) => handleInputChange("nomerazaosocial", e.target.value)}
                      placeholder={selectedCustomer.tipopessoa === "FISICA" ? "João da Silva" : "Empresa LTDA"}
                    />
                  </div>
                </div>

                {/* Contato */}
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 sm:gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="email" className="flex items-center gap-2 text-sm">
                      <Mail className="h-3 w-3 sm:h-4 sm:w-4" />
                      Email
                    </Label>
                    <Input
                      id="email"
                      type="email"
                      className=""
                      value={selectedCustomer.email || ""}
                      onChange={(e) => handleInputChange("email", e.target.value)}
                      placeholder="cliente@email.com"
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="telefone" className="flex items-center gap-2 text-sm">
                      <Phone className="h-3 w-3 sm:h-4 sm:w-4" />
                      Telefone
                    </Label>
                    <Input
                      id="telefone"
                      inputMode="tel"
                      className=""
                      value={formatTelefone(selectedCustomer.telefone) || ""}
                      onChange={(e) => {
                        const raw = e.target.value.replace(/\D/g, "").slice(0, 11);
                        handleInputChange("telefone", raw);
                      }}
                      placeholder="(11) 99999-9999"
                      maxLength={15}
                    />
                  </div>
                </div>
                <Separator className="mt-4" />
                {/* Endereço */}
                <div className="space-y-3 sm:space-y-4">
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 items-center gap-2">
                    <div className="space-y-2 sm:col-span-2 lg:col-span-1">
                      <Label htmlFor="cep" className="text-sm">
                        CEP
                      </Label>
                      <div className="relative">
                        {isLoadingCep ? (
                          <Loader2 className="absolute right-2 top-2.5 h-4 w-4 animate-spin text-primary" />
                        ) : (
                          <button
                            type="button"
                            onClick={handleGetCep}
                            className="absolute right-2 top-1.5 rounded-3xl p-1 transition-all hover:bg-gray-500/20"
                            aria-label="Consultar CEP"
                          >
                            <Search className="h-4 w-4" />
                          </button>
                        )}
                        <Input
                          id="cep"
                          className=""
                          value={formatCep(selectedCustomer.cep) || ""}
                          onChange={(e) => handleInputChange("cep", e.target.value)}
                          placeholder="00000-000"
                          maxLength={9}
                        />
                      </div>
                    </div>
                    <div className="space-y-2 lg:col-span-2">
                      <Label htmlFor="endereco" className="text-sm">
                        <MapPin className="h-4.5" />
                        Endereço Completo
                      </Label>
                      <Input
                        id="endereco"
                        className=""
                        value={selectedCustomer.endereco || ""}
                        onChange={(e) => handleInputChange("endereco", e.target.value)}
                        placeholder="Rua, número, complemento, bairro"
                      />
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="numero" className="text-sm">
                        Número
                      </Label>
                      <Input
                        id="endereconumero"
                        className=""
                        value={selectedCustomer.endereconumero || ""}
                        onChange={(e) => handleInputChange("endereconumero", e.target.value)}
                        placeholder="123"
                      />
                    </div>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-3 sm:grid-cols-2 sm:gap-4 lg:grid-cols-4">
                  <div className="min-w-0 space-y-2">
                    <Label htmlFor="estado" className="text-sm">
                      Estado
                    </Label>

                    <Popover open={open2} onOpenChange={setOpen2}>
                      <PopoverTrigger asChild>
                        <Button
                          variant="outline"
                          role="combobox"
                          aria-expanded={open2}
                          className="w-full justify-between"
                        >
                          {selectedCustomer.estado
                            ? ESTADOS_BRASIL.find((estado) => estado === selectedCustomer.estado)
                            : "Selecione..."}
                          <ChevronsUpDown className="opacity-50" />
                        </Button>
                      </PopoverTrigger>

                      <PopoverContent
                        className="w-[var(--radix-popover-trigger-width)] p-0"
                        onWheel={(e) => e.stopPropagation()}
                        onTouchMove={(e) => e.stopPropagation()}
                        onOpenAutoFocus={(e) => e.preventDefault()}
                      >
                        <Command>
                          <CommandInput placeholder="Buscar estado..." className="h-9 text-base" />
                          <CommandList className="max-h-45 overflow-y-auto overscroll-contain">
                            <CommandEmpty>Nenhum estado encontrada.</CommandEmpty>

                            {/* Aqui NÃO precisa de overflow/max-h */}
                            <CommandGroup>
                              {ESTADOS_BRASIL.map((estado, i) => (
                                <CommandItem
                                  className="hover:cursor-pointer"
                                  key={i}
                                  value={estado}
                                  onSelect={(currentValue) => {
                                    setselectedCustomer({
                                      ...selectedCustomer,
                                      estado: currentValue,
                                    });
                                    setOpen2(false);
                                  }}
                                >
                                  {estado}
                                  <Check
                                    className={cn(
                                      "ml-auto",
                                      selectedCustomer.estado === estado ? "opacity-100" : "opacity-0",
                                    )}
                                  />
                                </CommandItem>
                              ))}
                            </CommandGroup>
                          </CommandList>
                        </Command>
                      </PopoverContent>
                    </Popover>
                  </div>

                  <div className="min-w-0 space-y-2">
                    <Label htmlFor="cidade" className="text-sm">
                      Cidade
                    </Label>

                    <Popover open={open} onOpenChange={setOpen}>
                      <PopoverTrigger disabled={selectedCustomer.estado ? false : true} asChild>
                        <Button
                          variant="outline"
                          role="combobox"
                          aria-expanded={open}
                          className="w-full justify-between"
                        >
                          {selectedCustomer.cidade
                            ? cidades.find((cidade) => cidade.nome === selectedCustomer.cidade)?.nome
                            : loading
                              ? "Carregando..."
                              : selectedCustomer.estado
                                ? "Selecione..."
                                : "Selecione o estado"}
                          <ChevronsUpDown className="opacity-50" />
                        </Button>
                      </PopoverTrigger>

                      <PopoverContent
                        onWheel={(e) => e.stopPropagation()}
                        onTouchMove={(e) => e.stopPropagation()}
                        onOpenAutoFocus={(e) => e.preventDefault()}
                        className="w-[var(--radix-popover-trigger-width)] p-0"
                        onWheelCapture={(e) => e.stopPropagation()}
                      >
                        <Command>
                          <CommandInput placeholder="Buscar cidade..." className="h-9 text-base" />
                          <CommandList className="max-h-45 overflow-y-auto overscroll-contain">
                            <CommandEmpty>Nenhuma cidade encontrada.</CommandEmpty>

                            {/* Aqui NÃO precisa de overflow/max-h */}
                            <CommandGroup>
                              {cidades.map((cidade) => (
                                <CommandItem
                                  className="hover:cursor-pointer"
                                  key={cidade.id}
                                  value={cidade.nome}
                                  onSelect={() => {
                                    setselectedCustomer({
                                      ...selectedCustomer,
                                      cidade: cidade.nome,
                                      codigomunicipio: String(cidade.id),
                                    });
                                    setOpen(false);
                                  }}
                                >
                                  {cidade.nome}
                                  <Check
                                    className={cn(
                                      "ml-auto",
                                      selectedCustomer.cidade === cidade.nome ? "opacity-100" : "opacity-0",
                                    )}
                                  />
                                </CommandItem>
                              ))}
                            </CommandGroup>
                          </CommandList>
                        </Command>
                      </PopoverContent>
                    </Popover>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="bairro" className="text-sm">
                      Bairro
                    </Label>
                    <Input
                      id="bairro"
                      className=""
                      value={selectedCustomer.bairro || ""}
                      onChange={(e) => handleInputChange("bairro", e.target.value)}
                      placeholder="Ap, bloco..."
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="complemento" className="text-sm">
                      Complemento
                    </Label>
                    <Input
                      id="enderecocomplemento"
                      className=""
                      value={selectedCustomer.enderecocomplemento || ""}
                      onChange={(e) => handleInputChange("enderecocomplemento", e.target.value)}
                      placeholder="Ap, bloco..."
                    />
                  </div>
                </div>

                {/* Dados fiscais - Apenas para Pessoa Jurídica */}
                {selectedCustomer.tipopessoa === "JURIDICA" && (
                  <>
                    <Separator />
                    <div className="space-y-3 sm:space-y-4">
                      <div className="flex items-center gap-2">
                        <FileText className="h-3 w-3 sm:h-4 sm:w-4" />
                        <h3 className="text-base sm:text-lg font-semibold">Dados Fiscais</h3>
                      </div>

                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 sm:gap-4">
                        <div className="space-y-2">
                          <Label htmlFor="inscricaoestadual" className="text-sm">
                            Inscrição Estadual
                          </Label>
                          <Input
                            id="inscricaoestadual"
                            className=""
                            value={selectedCustomer.inscricaoestadual || ""}
                            onChange={(e) => handleInputChange("inscricaoestadual", e.target.value)}
                            placeholder="123456789"
                          />
                        </div>

                        <div className="space-y-2">
                          <Label htmlFor="inscricaomunicipal" className="text-sm">
                            Inscrição Municipal
                          </Label>
                          <Input
                            id="inscricaomunicipal"
                            className=""
                            value={selectedCustomer.inscricaomunicipal || ""}
                            onChange={(e) => handleInputChange("inscricaomunicipal", e.target.value)}
                            placeholder="123456789"
                          />
                        </div>
                      </div>

                      <div className="space-y-2">
                        <Label htmlFor="codigomunicipio" className="text-sm">
                          Código do Município
                        </Label>
                        <Input
                          id="codigomunicipio"
                          className=""
                          value={selectedCustomer.codigomunicipio || ""}
                          onChange={(e) => handleInputChange("codigomunicipio", e.target.value)}
                          placeholder="3550308"
                        />
                      </div>
                    </div>
                  </>
                )}

                {/* Botões */}
              </div>
            </TabsContent>

            {/* Exemplos para as outras abas (mantêm a mesma estrutura) */}
            <TabsContent value="Veículos" className="h-full min-h-0 overflow-hidden p-0">
              <div className="h-full min-h-0 overflow-auto rounded-md bg-muted-foreground/5 px-4 py-6 space-y-4 sm:px-6">
                <span
                  onClick={handleGetClienteVeiculos}
                  className="text-xs text-muted-foreground flex flex-row items-center gap-1 hover:cursor-pointer"
                >
                  Recarregar <Loader2 className={`w-3 h-3 ${isLoadingVeiculos && "animate-spin"}`} />
                </span>
                <div className="w-full flex flex-row justify-end">
                  <Button
                    disabled={isLoadingVeiculos || transferindo}
                    onClick={() => {
                      setOpenVehicle(true);
                    }}
                    className="text-xs hover:cursor-pointer"
                    variant={"outline"}
                  >
                    <Plus /> Veículo
                  </Button>
                </div>
                <Table className="text-xs">
                  <TableHeader>
                    <TableRow>
                      <TableHead className="text-center">ID</TableHead>
                      <TableHead className="text-center">Descrição</TableHead>
                      <TableHead className="text-center hidden md:table-cell">Placa</TableHead>
                      <TableHead className="text-center hidden md:table-cell">Cor</TableHead>
                      <TableHead className="text-center hidden md:table-cell">Fab/Mod</TableHead>
                      <TableHead className="text-center">Ações</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {selectedCustomer.veiculos.length > 0 ? (
                      selectedCustomer.veiculos.map((vehicle) => (
                        <TableRow key={vehicle.id} className="hover:cursor-pointer text-center">
                          <TableCell>{vehicle.id}</TableCell>
                          <TableCell>
                            <div className="flex flex-col text-left gap-1 md:hidden text-xs">
                              <span className="font-medium">
                                {vehicle.marca}/{vehicle.modelo}
                              </span>
                              <span className="text-muted-foreground">
                                {vehicle.placa} - {vehicle.ano} - {vehicle.cor}
                              </span>
                            </div>
                            <span className="hidden md:block">
                              {vehicle.marca}/{vehicle.modelo} {vehicle.versao}
                            </span>
                          </TableCell>
                          <TableCell className="hidden md:table-cell">{vehicle.placa}</TableCell>
                          <TableCell className="hidden md:table-cell">{vehicle.cor}</TableCell>
                          <TableCell className="hidden md:table-cell">{vehicle.ano}</TableCell>
                          <TableCell className="text-center items-center flex justify-center">
                            <DropdownMenu>
                              <DropdownMenuTrigger className="hover:cursor-pointer">
                                <Ellipsis className="w-4 h-4" />
                              </DropdownMenuTrigger>
                              <DropdownMenuContent className="text-xs">
                                <DropdownMenuItem
                                  onClick={() => {
                                    setSelectedVeiculoId(vehicle.id);
                                    setOpenVehicle(true);
                                  }}
                                  className="hover:cursor-pointer"
                                >
                                  <Pen />
                                  Editar
                                </DropdownMenuItem>
                                <DropdownMenuItem
                                  onClick={() => {
                                    setOpenCustomerSelect(true);
                                    setVeiculoTransferId(vehicle?.id);
                                  }}
                                  className="hover:cursor-pointer bg-blue-600/10 hover:bg-blue-600/20 data-[highlighted]:bg-blue-600/50 transition-all"
                                >
                                  <ArrowLeftRight />
                                  Transferir Propriedade
                                </DropdownMenuItem>
                              </DropdownMenuContent>
                            </DropdownMenu>
                          </TableCell>
                        </TableRow>
                      ))
                    ) : (
                      <TableRow>
                        <TableCell className="text-center h-20" colSpan={99}>
                          Cliente não possui veículos cadastrados
                        </TableCell>
                      </TableRow>
                    )}
                  </TableBody>
                </Table>
              </div>
            </TabsContent>

            <TabsContent
              value="Ordens"
              className="h-full min-h-0 min-w-0 overflow-y-auto overflow-x-hidden bg-muted-foreground/5 p-0"
            >
              <div className="h-full min-h-0 min-w-0 max-w-full space-y-4 overflow-auto px-2 py-3 sm:px-6 sm:py-6">
                <div className="flex min-w-0 flex-col gap-3 rounded-lg border bg-muted/20 p-4 sm:flex-row sm:items-center sm:justify-between">
                  <div className="min-w-0 space-y-1">
                    <div className="flex items-center gap-2">
                      <ClipboardList className="h-4 w-4 text-muted-foreground" />
                      <h3 className="text-sm font-semibold uppercase tracking-wide text-muted-foreground">
                        Ordens de Serviço
                      </h3>
                    </div>
                    <p className="text-xs text-muted-foreground">
                      Histórico de ordens de serviço vinculadas a este cliente.
                    </p>
                  </div>
                  <div className="flex items-center gap-2 rounded-md border bg-background px-3 py-1.5 shadow-sm">
                    <span className="text-xs font-medium text-muted-foreground">Total:</span>
                    <span className="text-sm font-bold">{selectedCustomer.ordens?.length ?? 0}</span>
                  </div>
                </div>

                <div className="w-full max-w-[calc(100vw-1rem)] overflow-hidden rounded-md border bg-card sm:max-w-full">
                  <div className="max-w-full overflow-x-auto">
                    <Table className="max-w-none text-xs">
                      <TableHeader className="bg-muted/50">
                        <TableRow>
                          <TableHead className="w-[90px]">ID</TableHead>
                          <TableHead>Data</TableHead>
                          <TableHead>Alvo</TableHead>
                          <TableHead>Detalhes</TableHead>
                          <TableHead>Descrição</TableHead>
                          <TableHead>Status</TableHead>
                          <TableHead className="text-right">Valor Total</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {selectedCustomer.ordens?.length > 0 ? (
                          selectedCustomer.ordens.map((ordem: any) => {
                            const dataOrdem = ordem.dataentrada || ordem.createdat || ordem.created_at;
                            const produtos = Array.isArray(ordem.produtos) ? ordem.produtos : [];
                            const servicos = Array.isArray(ordem.servicos) ? ordem.servicos : [];
                            const expanded = expandedOrdemId === ordem.id;
                            const alvoDescricao =
                              ordem.alvo_tipo === "PECA"
                                ? ordem.peca?.titulo || ordem.peca?.descricao || "Peça não informada"
                                : ordem.veiculo
                                  ? `${ordem.veiculo.marca ?? ""} ${ordem.veiculo.modelo ?? ""}`.trim() ||
                                  ordem.veiculo.modelo ||
                                  "Veículo vinculado"
                                  : "Veículo não informado";

                            return (
                              <Fragment key={ordem.id}>
                                <TableRow
                                  className="cursor-pointer transition-colors hover:bg-muted/50"
                                  onClick={() => setExpandedOrdemId(expanded ? null : ordem.id)}
                                >
                                  <TableCell className="font-medium text-muted-foreground">
                                    <span className="inline-flex items-center gap-1.5">
                                      <ChevronDown className={cn("h-3.5 w-3.5 transition-transform", expanded && "rotate-180")} />
                                      #{ordem.id}
                                    </span>
                                  </TableCell>
                                  <TableCell>{formatDate(dataOrdem)}</TableCell>
                                  <TableCell>{ordem.alvo_tipo === "PECA" ? "Peça" : "Veículo"}</TableCell>
                                  <TableCell className="max-w-[180px]">
                                    <div className="flex flex-col gap-1">
                                      <span className="truncate" title={alvoDescricao}>
                                        {alvoDescricao}
                                      </span>
                                      {ordem.alvo_tipo === "PECA" && ordem.peca?.lacre ? (
                                        <span className="text-[11px] text-muted-foreground">Lacre: {ordem.peca.lacre}</span>
                                      ) : null}
                                      {ordem.alvo_tipo !== "PECA" && ordem.veiculo?.placa ? (
                                        <span className="text-[11px] text-muted-foreground">Placa: {ordem.veiculo.placa}</span>
                                      ) : null}
                                    </div>
                                  </TableCell>
                                  <TableCell className="max-w-[220px]">
                                    <div className="flex flex-col gap-1">
                                      <span className="truncate font-medium" title={ordem.descricao || ""}>
                                        {ordem.descricao || "Sem descrição"}
                                      </span>
                                      {ordem.prioridade ? (
                                        <span className="text-[11px] text-muted-foreground">
                                          Prioridade: {String(ordem.prioridade)}
                                        </span>
                                      ) : null}
                                    </div>
                                  </TableCell>
                                  <TableCell>{getStatusBadge(ordem.status)}</TableCell>
                                  <TableCell className="text-right font-medium">
                                    {formatCurrency(ordem.orcamentototal || 0)}
                                  </TableCell>
                                </TableRow>
                                {expanded ? (
                                  <TableRow className="bg-muted/20">
                                    <TableCell colSpan={7} className="p-3">
                                      <div className="grid min-w-[760px] grid-cols-2 gap-3">
                                        <div className="rounded-md border bg-background p-3">
                                          <p className="mb-2 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
                                            Serviços
                                          </p>
                                          {servicos.length > 0 ? (
                                            <div className="space-y-2">
                                              {servicos.map((item: any, index: number) => (
                                                <div key={`${ordem.id}-servico-${index}`} className="flex items-center justify-between gap-3 text-xs">
                                                  <span className="truncate" title={item.servico?.descricao || ""}>
                                                    {item.servico?.descricao || "Serviço"}
                                                  </span>
                                                  <span className="shrink-0 font-medium">
                                                    {formatCurrency(item.subtotal || 0)}
                                                  </span>
                                                </div>
                                              ))}
                                            </div>
                                          ) : (
                                            <p className="text-xs text-muted-foreground">Nenhum serviço vinculado.</p>
                                          )}
                                        </div>

                                        <div className="rounded-md border bg-background p-3">
                                          <p className="mb-2 text-xs font-semibold uppercase tracking-wide text-muted-foreground">
                                            Produtos
                                          </p>
                                          {produtos.length > 0 ? (
                                            <div className="space-y-2">
                                              {produtos.map((item: any, index: number) => (
                                                <div key={`${ordem.id}-produto-${index}`} className="flex items-center justify-between gap-3 text-xs">
                                                  <span className="truncate" title={item.produto?.titulo || ""}>
                                                    {item.produto?.titulo || "Produto"}
                                                  </span>
                                                  <span className="shrink-0 font-medium">
                                                    {formatCurrency(item.subtotal || 0)}
                                                  </span>
                                                </div>
                                              ))}
                                            </div>
                                          ) : (
                                            <p className="text-xs text-muted-foreground">Nenhum produto vinculado.</p>
                                          )}
                                        </div>
                                      </div>
                                    </TableCell>
                                  </TableRow>
                                ) : null}
                              </Fragment>
                            );
                          })
                        ) : (
                          <TableRow>
                            <TableCell className="h-20 text-center" colSpan={7}>
                              Cliente não possui ordens cadastradas
                            </TableCell>
                          </TableRow>
                        )}
                      </TableBody>
                    </Table>
                  </div>
                </div>
              </div>
            </TabsContent>
          </Tabs>

          <DialogShellFooter className="border-t px-4 py-3 sm:px-6">
            <div className="flex w-full flex-row justify-end gap-2">
              <DialogShellClose asChild>
                <Button
                  type="button"
                  className="h-9 min-w-24 hover:cursor-pointer"
                  variant="outline"
                >
                  Cancelar
                </Button>
              </DialogShellClose>
              <Button
                type="button"
                disabled={isSubmitting}
                className="h-9 min-w-24 text-sm hover:cursor-pointer"
                onClick={handleUpdateCustomer}
              >
                {isSubmitting ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    Salvando...
                  </>
                ) : (
                  "Salvar"
                )}
              </Button>
            </div>
          </DialogShellFooter>
        </div>
        <CustomerSelect
          open={openCustomerSelect}
          setOpen={setOpenCustomerSelect}
          OnSelect={(c) => handleVehicleTransfer(c.id)}
        />
      </DialogShellContent>
    );
  }
}

﻿"use client";

import { useGetCidades } from "@/app/(app)/hooks/useGetCidades";
import { Avatar,AvatarFallback,AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import {
Command,
CommandEmpty,
CommandGroup,
CommandInput,
CommandItem,
CommandList,
} from "@/components/ui/command";
import {
DialogClose,
DialogContent,
DialogDescription,
DialogFooter,
DialogHeader,
DialogTitle,
} from "@/components/ui/dialog";
import { DrawerClose,DrawerContent,DrawerDescription,DrawerFooter,DrawerHeader,DrawerTitle } from "@/components/ui/drawer";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
Popover,
PopoverContent,
PopoverTrigger,
} from "@/components/ui/popover";
import {
Select,
SelectContent,
SelectItem,
SelectTrigger,
SelectValue,
} from "@/components/ui/select";
import { Separator } from "@/components/ui/separator";
import {
Tooltip,
TooltipContent,
TooltipTrigger,
} from "@/components/ui/tooltip";
import { cn } from "@/lib/utils";
import axios,{ isAxiosError } from "axios";
import {
Building2,
Camera,
Check,
ChevronsUpDown,
FileText,
IdCard,
Loader2,
Mail,
MapPin,
Phone,
Search,
User,
} from "lucide-react";
import { useEffect,useState } from "react";
import { toast } from "sonner";
import { Customer } from "../../types";
import {
ESTADOS_BRASIL,
NewCustomer,
StatusCliente,
TipoPessoa,
} from "./types";
import { formatCep,formatCpfCnpj,formatTelefone } from "./utils";

interface RegisterContentProps {
  newCustomer: NewCustomer;
  setNewCustomer: (value: NewCustomer) => void;
  setSelectedCustomerId?: (value: number | undefined) => void;
  onRegister?: (c: Customer) => void;
  isDesktop?: boolean;
}

const statusOptionClass: Record<StatusCliente, string> = {
  ATIVO:
    "bg-emerald-100 text-emerald-800 focus:bg-emerald-100 focus:text-emerald-800 dark:bg-emerald-950/50 dark:text-emerald-300 dark:focus:bg-emerald-950/50 dark:focus:text-emerald-300",
  INATIVO:
    "bg-slate-100 text-slate-800 focus:bg-slate-100 focus:text-slate-800 dark:bg-slate-900 dark:text-slate-300 dark:focus:bg-slate-900 dark:focus:text-slate-300",
  PENDENTE:
    "bg-amber-100 text-amber-800 focus:bg-amber-100 focus:text-amber-800 dark:bg-amber-950/50 dark:text-amber-300 dark:focus:bg-amber-950/50 dark:focus:text-amber-300",
};

const statusLabel: Record<StatusCliente, string> = {
  ATIVO: "Ativo",
  INATIVO: "Inativo",
  PENDENTE: "Pendente",
};

export default function RegisterContent({
  newCustomer,
  setNewCustomer,
  setSelectedCustomerId,
  onRegister,
  isDesktop = true,
}: RegisterContentProps) {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { cidades, loading } = useGetCidades(newCustomer?.estado);
  const [open, setOpen] = useState(false);
  const [isLoadingCep, setIsLoadingCep] = useState(false);
  const [isLoadingCNPJ, setIsLoadingCNPJ] = useState(false);
  const [open2, setOpen2] = useState(false);

  const handleInputChange = (field: keyof NewCustomer, value: string) => {
    setNewCustomer({ ...newCustomer, [field]: value });
  };

  const handleGetCep = async () => {
    if (!newCustomer.cep) {
      toast.error("Informe um CEP para buscar");
      return;
    }
    setIsLoadingCep(true);
    try {
      const response = await axios.get(
        `https://opencep.com/v1/${newCustomer.cep}`
      );
      if (response.status === 200) {
        console.log(response);
        const enderecoResponse = response.data;
        setNewCustomer({
          ...newCustomer,
          endereco: enderecoResponse.logradouro,
          cidade: enderecoResponse.localidade,
          codigomunicipio: String(enderecoResponse.ibge),
          estado: enderecoResponse.uf,
          bairro: enderecoResponse.bairro,
        });
      }
    } catch (error) {
      if (isAxiosError(error)) {
        if (error.status === 404) {
          toast.error("CEP não encontrado.");
        }
      }
    } finally {
      setIsLoadingCep(false);
    }
  };

  const handleGetCNPJ = async () => {
    if (newCustomer.cpfcnpj.length < 14) {
      toast.warning("CPF inválido para consulta de CNPJ");

      return;
    }
    setIsLoadingCNPJ(true);
    try {
      const response = await axios.get(
        `https://publica.cnpj.ws/cnpj/${newCustomer.cpfcnpj}`
      );
      if (response.status === 200) {
        console.log(response.data);
        const juridica = response.data;
        setNewCustomer({
          ...newCustomer,
          nomerazaosocial: juridica.razao_social,
          cep: juridica.estabelecimento.cep,
          email: juridica.estabelecimento.email,
          endereconumero: juridica.estabelecimento.numero,
          telefone: `${juridica.estabelecimento.ddd1}${juridica.estabelecimento.telefone1}`,
          estado: juridica.estabelecimento.estado.sigla,
          cidade: juridica.estabelecimento.cidade.nome,
          codigomunicipio: String(juridica.estabelecimento.cidade.ibge_id),
          endereco: juridica.estabelecimento.logradouro,
          enderecocomplemento: juridica.estabelecimento.complemento,
          bairro: juridica.estabelecimento.bairro,
        });
      }
    } catch (error) {
      if (isAxiosError(error)) {
        if (error.status === 429) {
          toast.error("Muitas tentativas", {
            description: "Aguarde um pouco e tente novamente",
          });
        }
        if (error.status === 400) {
          toast.error("CNPJ não encontrado", {
            description: "Verifique o dado informado",
          });
        }
        if (error.status === 404) {
          toast.error("Erro no servidor de consulta", {
            description: "Verifique com o administrador",
          });
        }
      }
    } finally {
      setIsLoadingCNPJ(false);
    }
  };

  function validarEmailDigitado(email: string): boolean {
    const valor = email.trim();
    if (!valor) return true;

    // Mesmo regex usado na constraint (case-insensitive)
    const regex = /^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}$/i;

    return regex.test(valor);
  }

  const handleCreateCustomer = async () => {
    if (!validarEmailDigitado(newCustomer?.email || "")) {
      toast.warning("Insira um email válido")
      return
    }
    setIsSubmitting(true);
    try {
      const response = await axios.post("/api/customers", {
        newCustomer,
      });

      if (response.status === 201) {
        console.log(response.data.data);
        toast.success("Sucesso!", {
          description: "Cliente cadastrado.",
          duration: 2000,
        });
        if (setSelectedCustomerId) {
          setSelectedCustomerId(response.data.id);
        }
        onRegister?.(response.data.data);
        setNewCustomer({
          tipopessoa: "FISICA",
          cpfcnpj: "",
          nomerazaosocial: "",
          email: "",
          bairro: "",
          telefone: "",
          endereco: "",
          enderecocomplemento: "",
          endereconumero: "",
          cidade: "",
          estado: "",
          cep: "",
          inscricaoestadual: "",
          inscricaomunicipal: "",
          codigomunicipio: "",
          status: "ATIVO",
          foto: "",
        });
      }
    } catch (error) {
      if (isAxiosError(error)) {
        toast.error("Erro", {
          description: error.response?.data.error,
          duration: 2000,
        });

        console.log(error);
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  useEffect(() => {
    setNewCustomer({
      ...newCustomer,
      tipopessoa: newCustomer.tipopessoa,
      cpfcnpj: "",
      nomerazaosocial: "",
    });
  }, [newCustomer.tipopessoa]);

  useEffect(() => {
    if (newCustomer.tipopessoa === "JURIDICA" && newCustomer.cpfcnpj.length === 14) {
      handleGetCNPJ();
    }
  }, [newCustomer.cpfcnpj, newCustomer.tipopessoa]);

  useEffect(() => {
    console.log(newCustomer)
  }, [newCustomer])

  const DialogShellContent = isDesktop ? DialogContent : DrawerContent;
  const DialogShellHeader = isDesktop ? DialogHeader : DrawerHeader;
  const DialogShellFooter = isDesktop ? DialogFooter : DrawerFooter;
  const DialogShellTitle = isDesktop ? DialogTitle : DrawerTitle;
  const DialogShellDescription = isDesktop ? DialogDescription : DrawerDescription;
  const DialogShellClose = isDesktop ? DialogClose : DrawerClose;
 
  return (
    // <DialogContent className="h-dvh sm:max-w-[1100px] w-[95vw] p-2 overflow-hidden">
    <DialogShellContent className="h-svh w-screen max-w-none p-0 overflow-hidden sm:max-h-[850px] sm:w-[95vw] sm:max-w-[1100px] sm:min-w-0">
      <div className="flex h-full min-h-0 flex-col">
        <DialogShellHeader className="shrink-0 border-b px-4 py-3 sm:px-6">
          <DialogShellTitle className="text-sm sm:text-lg">
            Cliente
            <span className="text-muted-foreground text-sm font-light"> | Novo </span>
          </DialogShellTitle>
          <DialogShellDescription>
            Preencha dados para registrar um novo cliente
          </DialogShellDescription>
        </DialogShellHeader>

        {/* CONTEÚDO DA ABA: o scroll fica no wrapper interno */}

        <div className="h-full min-h-0 overflow-auto bg-muted-foreground/5 px-4 py-4 space-y-6 sm:px-6">
          <div className="rounded-lg border bg-card p-4">
            <div className="flex flex-col gap-4 sm:flex-row sm:items-center">
              <div className="flex items-center gap-3">
                <div className="relative shrink-0">
                  <Avatar className="h-12 w-12 sm:h-14 sm:w-14">
                <AvatarImage
                  // src={fotoPreview || "/placeholder.svg"}
                  alt="Foto do cliente"
                />
                <AvatarFallback className="text-sm">
                  {newCustomer.tipopessoa === "FISICA" ? (
                    <User className="h-5 w-5 sm:h-6 sm:w-6" />
                  ) : (
                    <Building2 className="h-5 w-5 sm:h-6 sm:w-6" />
                  )}
                </AvatarFallback>
              </Avatar>
              <Label
                htmlFor="foto-upload"
                className="absolute -bottom-1 -right-1 cursor-pointer"
              >
                <div className="rounded-full bg-primary p-1.5 text-primary-foreground transition-colors hover:bg-primary/90">
                  <Camera className="h-3 w-3" />
                </div>
                <input
                  id="foto-upload"
                  type="file"
                  accept="image/*"
                  className="hidden"
                />
              </Label>
                </div>
                <div className="space-y-1">
                  <p className="text-sm font-semibold">
                    {newCustomer.nomerazaosocial?.trim() || "Novo cliente"}
                  </p>
                  <p className="text-xs text-muted-foreground">
                    Defina o perfil e complete os dados cadastrais.
                  </p>
                </div>
              </div>

              <div className="grid flex-1 grid-cols-2 gap-3">
                <div className="space-y-2">
                  <Label htmlFor="status" className="text-sm">
                    Status
                  </Label>
                  <Select
                    value={newCustomer.status || ""}
                    onValueChange={(value: StatusCliente) =>
                      handleInputChange("status", value)
                    }
                  >
                    <SelectTrigger className={cn("h-10 sm:h-11", statusOptionClass[newCustomer.status])}>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem
                        value="ATIVO"
                        className={cn("px-2 py-1.5 text-sm font-medium", statusOptionClass.ATIVO)}
                      >
                        {statusLabel.ATIVO}
                      </SelectItem>
                      <SelectItem
                        value="INATIVO"
                        className={cn("px-2 py-1.5 text-sm font-medium", statusOptionClass.INATIVO)}
                      >
                        {statusLabel.INATIVO}
                      </SelectItem>
                      <SelectItem
                        value="PENDENTE"
                        className={cn("px-2 py-1.5 text-sm font-medium", statusOptionClass.PENDENTE)}
                      >
                        {statusLabel.PENDENTE}
                      </SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label htmlFor="tipopessoa" className="text-sm">
                    Tipo de Pessoa *
                  </Label>
                  <Select
                    value={newCustomer.tipopessoa}
                    onValueChange={(value: TipoPessoa) =>
                      handleInputChange("tipopessoa", value)
                    }
                  >
                    <SelectTrigger className="h-10 sm:h-11">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="FISICA">
                        <div className="flex items-center gap-2">
                          <User className="h-4 w-4" />
                          <span className="text-sm">Pessoa Física</span>
                        </div>
                      </SelectItem>
                      <SelectItem value="JURIDICA">
                        <div className="flex items-center gap-2">
                          <Building2 className="h-4 w-4" />
                          <span className="text-sm">Pessoa Jurídica</span>
                        </div>
                      </SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
            </div>
          </div>

          {/* Dados Principais */}
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 sm:gap-4">
            <div className="space-y-2">
              <Label htmlFor="cpfcnpj" className="text-sm">
                {newCustomer.tipopessoa === "FISICA" ? "CPF" : "CNPJ"} *
              </Label>
              <div className="relative">
                {isLoadingCNPJ && (
                  <Loader2 className="absolute right-9 top-2.5 h-4 w-4 animate-spin text-primary" />
                )}
                <div className="relative">
                  {newCustomer.tipopessoa === "JURIDICA" ? (
                    <Tooltip>
                      <TooltipTrigger asChild>
                        <button
                          type="button"
                          onClick={handleGetCNPJ}
                          className="absolute right-2 top-1.5 rounded-3xl p-1 transition-all hover:bg-gray-500/20"
                          aria-label="Consultar CNPJ"
                        >
                          <IdCard className="h-4 w-4" />
                        </button>
                      </TooltipTrigger>
                      <TooltipContent>Consultar CNPJ</TooltipContent>
                    </Tooltip>
                  ) : null}
                  <Input
                    inputMode="numeric"
                    id="cpfcnpj"
                    className=""
                    value={
                      formatCpfCnpj(
                        newCustomer.cpfcnpj,
                        newCustomer.tipopessoa
                      ) || ""
                    }
                    onChange={(e) => {
                      const onlyNumbers = e.target.value.replace(/\D/g, "");

                      handleInputChange("cpfcnpj", onlyNumbers);
                    }}
                    placeholder={
                      newCustomer.tipopessoa === "FISICA"
                        ? "000.000.000-00"
                        : "00.000.000/0000-00"
                    }
                    maxLength={newCustomer.tipopessoa === "FISICA" ? 14 : 18}
                  />
                </div>
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="nomerazaosocial" className="text-sm">
                {newCustomer.tipopessoa === "FISICA"
                  ? "Nome Completo"
                  : "Razão Social"}{" "}
                *
              </Label>
              <Input
                id="nomerazaosocial"
                className=""
                value={newCustomer.nomerazaosocial || ""}
                onChange={(e) =>
                  handleInputChange("nomerazaosocial", e.target.value)
                }
                placeholder={
                  newCustomer.tipopessoa === "FISICA"
                    ? "João da Silva"
                    : "Empresa LTDA"
                }
              />
            </div>
          </div>

          {/* Contato */}
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 sm:gap-4">
            <div className="space-y-2">
              <Label
                htmlFor="email"
                className="flex items-center gap-2 text-sm"
              >
                <Mail className="h-3 w-3 sm:h-4 sm:w-4" />
                Email
              </Label>
              <Input
                inputMode="email"
                id="email"
                type="email"
                className=""
                value={newCustomer.email || ""}
                onChange={(e) => handleInputChange("email", e.target.value)}
                placeholder="cliente@email.com"
              />
            </div>

            <div className="space-y-2">
              <Label
                htmlFor="telefone"
                className="flex items-center gap-2 text-sm"
              >
                <Phone className="h-3 w-3 sm:h-4 sm:w-4" />
                Telefone *
              </Label>
              <Input
                inputMode="tel"
                id="telefone"
                className=""
                value={formatTelefone(newCustomer.telefone) || ""}
                onChange={(e) => {
                  const raw = e.target.value.replace(/\D/g, "").slice(0, 11);
                  handleInputChange("telefone", raw);
                }}
                placeholder="(11) 99999-9999"
                maxLength={15}
              />
            </div>
          </div>
          <Separator className="mt-4" />
          {/* Endereço */}
          <div className="space-y-3 sm:space-y-4">
            {/* <div className="flex items-center gap-2">
              <MapPin className="h-3 w-3 sm:h-4 sm:w-4" />
              <h3 className="text-base font-semibold sm:text-lg">Endereço</h3>
            </div> */}

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 items-center gap-2">
              <div className="space-y-2 sm:col-span-2 lg:col-span-1">
                <Label htmlFor="cep" className="text-sm">
                  CEP
                </Label>
                <div className="relative">
                  {isLoadingCep ? (
                    <Loader2 className="absolute right-2 top-2.5 h-4 w-4 animate-spin text-primary" />
                  ) : (
                    <button
                      type="button"
                      onClick={handleGetCep}
                      className="absolute right-2 top-1.5 rounded-3xl p-1 transition-all hover:bg-gray-500/20"
                      aria-label="Consultar CEP"
                    >
                      <Search className="h-4 w-4" />
                    </button>
                  )}
                  <Input
                    id="cep"
                    className=""
                    value={formatCep(newCustomer.cep) || ""}
                    onChange={(e) => handleInputChange("cep", e.target.value)}
                    placeholder="00000-000"
                    maxLength={9}
                  />
                </div>
              </div>
              <div className="space-y-2 lg:col-span-2">
                <Label htmlFor="endereco" className="text-sm">
                  <MapPin className="h-4.5" />
                  Endereço Completo
                </Label>
                <Input
                  id="endereco"
                  className=""
                  value={newCustomer.endereco || ""}
                  onChange={(e) =>
                    handleInputChange("endereco", e.target.value)
                  }
                  placeholder="Rua, avenida..."
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="numero" className="text-sm">
                  Número
                </Label>
                <Input
                  id="endereconumero"
                  className=""
                  value={newCustomer.endereconumero || ""}
                  onChange={(e) =>
                    handleInputChange("endereconumero", e.target.value)
                  }
                  placeholder="123"
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-3 sm:grid-cols-2 sm:gap-4 lg:grid-cols-4">
              <div className="min-w-0 space-y-2">
                <Label htmlFor="estado" className="text-sm">
                  Estado
                </Label>

                <Popover open={open2} onOpenChange={setOpen2}>
                  <PopoverTrigger asChild>
                    <Button
                      variant="outline"
                      role="combobox"
                      aria-expanded={open2}
                      className="w-full justify-between"
                    >
                      {newCustomer.estado
                        ? ESTADOS_BRASIL.find(
                          (estado) => estado === newCustomer.estado
                        )
                        : "Selecione..."}
                      <ChevronsUpDown className="opacity-50" />
                    </Button>
                  </PopoverTrigger>

                  <PopoverContent
                    onWheel={(e) => e.stopPropagation()}
                    onTouchMove={(e) => e.stopPropagation()}
                    onOpenAutoFocus={(e) => e.preventDefault()}
                    className="w-[var(--radix-popover-trigger-width)] p-0"
                    onWheelCapture={(e) => e.stopPropagation()}
                  >
                    <Command>
                      <CommandInput
                        placeholder="Buscar estado..."
                        className="h-9 text-base"
                      />
                      <CommandList className="max-h-45 overflow-y-auto overscroll-contain">
                        <CommandEmpty>Nenhum estado encontrada.</CommandEmpty>

                        {/* Aqui NÃO precisa de overflow/max-h */}
                        <CommandGroup>
                          {ESTADOS_BRASIL.map((estado, i) => (
                            <CommandItem
                              className="hover:cursor-pointer"
                              key={i}
                              value={estado}
                              onSelect={(currentValue) => {
                                setNewCustomer({
                                  ...newCustomer,
                                  estado: currentValue,
                                });
                                setOpen2(false);
                              }}
                            >
                              {estado}
                              <Check
                                className={cn(
                                  "ml-auto",
                                  newCustomer.estado === estado
                                    ? "opacity-100"
                                    : "opacity-0"
                                )}
                              />
                            </CommandItem>
                          ))}
                        </CommandGroup>
                      </CommandList>
                    </Command>
                  </PopoverContent>
                </Popover>
              </div>

              <div className="min-w-0 space-y-2">
                <Label htmlFor="cidade" className="text-sm">
                  Cidade
                </Label>

                <Popover open={open} onOpenChange={setOpen}>
                  <PopoverTrigger
                    disabled={newCustomer.estado ? false : true}
                    asChild
                  >
                    <Button
                      variant="outline"
                      role="combobox"
                      aria-expanded={open}
                      className="w-full justify-between"
                    >
                      {newCustomer.cidade
                        ? cidades.find(
                          (cidade) => cidade.nome === newCustomer.cidade
                        )?.nome
                        : loading
                          ? "Carregando..."
                          : newCustomer.estado
                            ? "Selecione..."
                            : "Selecione o estado"}
                      <ChevronsUpDown className="opacity-50" />
                    </Button>
                  </PopoverTrigger>

                  <PopoverContent
                    onWheel={(e) => e.stopPropagation()}
                    onTouchMove={(e) => e.stopPropagation()}
                    onOpenAutoFocus={(e) => e.preventDefault()}
                    className="w-[var(--radix-popover-trigger-width)] p-0"
                    onWheelCapture={(e) => e.stopPropagation()}
                  >
                    <Command>
                      <CommandInput
                        placeholder="Buscar cidade..."
                        className="h-9 text-base"
                      />
                      <CommandList className="max-h-45 overflow-y-auto overscroll-contain">
                        <CommandEmpty>Nenhuma cidade encontrada.</CommandEmpty>

                        {/* Aqui NÃO precisa de overflow/max-h */}
                        <CommandGroup>
                          {cidades.map((cidade) => (
                            <CommandItem
                              key={cidade.id}
                              value={cidade.nome} // string
                              onSelect={() => {
                                setNewCustomer({
                                  ...newCustomer,
                                  cidade: cidade.nome,
                                  codigomunicipio: String(cidade.id),
                                });
                                setOpen(false);
                              }}
                              className="hover:cursor-pointer"
                            >
                              {cidade.nome}
                              <Check
                                className={cn(
                                  "ml-auto",
                                  newCustomer.cidade === cidade.nome ? "opacity-100" : "opacity-0"
                                )}
                              />
                            </CommandItem>
                          ))}
                        </CommandGroup>

                      </CommandList>
                    </Command>
                  </PopoverContent>
                </Popover>
              </div>
              <div className="space-y-2">
                <Label htmlFor="cidade" className="text-sm">
                  Bairro
                </Label>
                <Input
                  id="bairro"
                  className=""
                  value={newCustomer.bairro || ""}
                  onChange={(e) => handleInputChange("bairro", e.target.value)}
                  placeholder="Bairro..."
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="complemento" className="text-sm">
                  Complemento
                </Label>
                <Input
                  id="enderecocomplemento"
                  className=""
                  value={newCustomer.enderecocomplemento || ""}
                  onChange={(e) =>
                    handleInputChange("enderecocomplemento", e.target.value)
                  }
                  placeholder="Ap, Bloco..."
                />
              </div>
            </div>
          </div>

          {/* Dados fiscais - Apenas para Pessoa Jurídica */}
          {newCustomer.tipopessoa === "JURIDICA" && (
            <>
              <Separator />
              <div className="space-y-3 sm:space-y-4">
                <div className="flex items-center gap-2">
                  <FileText className="h-3 w-3 sm:h-4 sm:w-4" />
                  <h3 className="text-base sm:text-lg font-semibold">
                    Dados Fiscais
                  </h3>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 sm:gap-4">
                  <div className="space-y-2">
                    <Label
                      htmlFor="inscricaoestadual"
                      className="text-sm"
                    >
                      Inscrição Estadual
                    </Label>
                    <Input
                      id="inscricaoestadual"
                      className=""
                      value={newCustomer.inscricaoestadual || ""}
                      onChange={(e) =>
                        handleInputChange("inscricaoestadual", e.target.value)
                      }
                      placeholder="123456789"
                    />
                  </div>

                  <div className="space-y-2">
                    <Label
                      htmlFor="inscricaomunicipal"
                      className="text-sm"
                    >
                      Inscrição Municipal
                    </Label>
                    <Input
                      id="inscricaomunicipal"
                      className=""
                      value={newCustomer.inscricaomunicipal || ""}
                      onChange={(e) =>
                        handleInputChange("inscricaomunicipal", e.target.value)
                      }
                      placeholder="123456789"
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <Label
                    htmlFor="codigomunicipio"
                    className="text-sm"
                  >
                    Código do Município
                  </Label>
                  <Input
                    id="codigomunicipio"
                    className=""
                    value={newCustomer.codigomunicipio || ""}
                    onChange={(e) =>
                      handleInputChange("codigomunicipio", e.target.value)
                    }
                    placeholder="3550308"
                  />
                </div>
              </div>
            </>
          )}

          {/* Botões */}
        </div>
        <DialogShellFooter className="border-t px-4 py-3 sm:px-6">
          <div className="flex w-full flex-row justify-end gap-2">
            <DialogShellClose asChild>
              <Button
                type="button"
                className="h-9 min-w-24 hover:cursor-pointer"
                variant="outline"
              >
                Cancelar
              </Button>
            </DialogShellClose>
            <Button
              type="button"
              disabled={isSubmitting}
              onClick={handleCreateCustomer}
              className="h-9 min-w-24 text-sm hover:cursor-pointer"
            >
              {isSubmitting ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  Salvando...
                </>
              ) : (
                "Salvar"
              )}
            </Button>
          </div>
        </DialogShellFooter>
      </div>
    </DialogShellContent>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import type { ChecklistTemplate, ItemChecklist } from "./types";
import { uid } from "./utils";

import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { Plus, X, Save, Edit3 } from "lucide-react";
import { ItemDialog } from "./item-dialog";
import { Switch } from "@/components/ui/switch";

import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";

type Props = {
  value: ChecklistTemplate;
  categorias: ReadonlyArray<string>;
  editando?: boolean;
  onSave: (tpl: ChecklistTemplate) => Promise<void> | void;
  onCancel: () => void;
  variant?: "card" | "bare";
  onChange?: (tpl: ChecklistTemplate) => void;
  exposeSubmit?: (fn: () => Promise<void> | void) => void;
};

export function TemplateForm({
  value,
  categorias,
  editando,
  onSave,
  onCancel,
  variant = "card",
  onChange,
  exposeSubmit,
}: Props) {
  // inicializa uma vez com "ativo" default true
  const [tpl, setTpl] = useState<ChecklistTemplate>(() => ({
    ...value,
    ativo: value.ativo ?? true,
  }));

  const [addOpen, setAddOpen] = useState(false);
  const [editItemOpen, setEditItemOpen] = useState(false);
  const [itemEditando, setItemEditando] = useState<ItemChecklist | null>(null);

  // se você quiser que ao trocar totalmente de modelo (outro id) resete o form:
  useEffect(() => {
    setTpl((prev) => {
      if (prev.id === value.id) return prev; // evita loop
      return { ...value, ativo: value.ativo ?? true };
    });
  }, [value.id, value.ativo, value.nome, value.descricao]); // depende do id (principalmente)

  // sobe alterações pro pai, pra ele conseguir validar/usar
  useEffect(() => {
    onChange?.(tpl);
  }, [tpl, onChange]);

  // garante que a categoria atual (vinda do banco) apareça no select,
  // mesmo se não estiver em `categorias`
  const categoriasSelect = useMemo(() => {
    if (!tpl.categoria) return categorias;
    if (categorias.includes(tpl.categoria)) return categorias;
    return [tpl.categoria, ...categorias];
  }, [categorias, tpl.categoria]);

  const adicionarItem = (it: Partial<ItemChecklist>) => {
    const novo: ItemChecklist = {
      id: uid(),
      titulo: (it.titulo ?? "").trim(),
      descricao: (it.descricao ?? "").trim(),
      obrigatorio: !!it.obrigatorio,
      categoria: it.categoria ?? "",
    };
    setTpl((prev) => ({ ...prev, itens: [...prev.itens, novo] }));
  };

  const atualizarItem = (it: Partial<ItemChecklist> & { id: string }) => {
    setTpl((prev) => ({
      ...prev,
      itens: prev.itens.map((i) =>
        i.id === it.id ? ({ ...i, ...it } as ItemChecklist) : i
      ),
    }));
  };

  const removerItem = (id: string) => {
    setTpl((prev) => ({
      ...prev,
      itens: prev.itens.filter((i) => i.id !== id),
    }));
  };

  const salvar = async () => {
    if (!tpl.nome.trim() || tpl.itens.length === 0) return;

    const toSave: ChecklistTemplate = {
      ...tpl,
      id: tpl.id || uid(),
      criadoEm: tpl.criadoEm || new Date().toISOString(),
      ativo: tpl.ativo ?? true,
    };

    await onSave(toSave);
  };

  // expõe função de submit pro DialogFooter
  useEffect(() => {
    exposeSubmit?.(salvar);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [tpl, exposeSubmit]);

  const Content = (
    <div className="space-y-6">
      {/* Dados do modelo */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div className="space-y-2">
          <Label htmlFor="nome">Nome do checklist</Label>
          <Input
            id="nome"
            placeholder="Ex.: Inspeção de entrada"
            value={tpl.nome}
            onChange={(e) =>
              setTpl((p) => ({ ...p, nome: e.target.value }))
            }
          />
        </div>

        <div className="space-y-2">
          <Label htmlFor="categoria">Categoria</Label>
          <Select
            value={tpl.categoria || ""}
            onValueChange={(v) =>
              setTpl((p) => ({ ...p, categoria: v }))
            }
          >
            <SelectTrigger id="categoria">
              <SelectValue placeholder="Selecione..." />
            </SelectTrigger>
            <SelectContent>
              {categoriasSelect.map((c) => (
                <SelectItem key={c} value={c}>
                  {c}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        <div className="sm:col-span-2 space-y-2">
          <Label htmlFor="descricao">Descrição</Label>
          <Textarea
            id="descricao"
            placeholder="Uma descrição curta para identificar o checklist…"
            value={tpl.descricao || ""}
            onChange={(e) =>
              setTpl((p) => ({ ...p, descricao: e.target.value }))
            }
            rows={3}
          />
        </div>
      </div>

      {/* Status (ativo / inativo) */}
      <div className="mt-1 flex items-center justify-between rounded-md border px-3 py-2 bg-muted/40">
        <div className="space-y-0.5">
          <span className="text-sm font-medium">Checklist ativo</span>
          <p className="text-xs text-muted-foreground">
            Quando inativo, este modelo não aparecerá para seleção nas ordens de serviço.
          </p>
        </div>
        <div className="flex items-center gap-2">
          <span className="text-xs text-muted-foreground hidden sm:inline">
            {tpl.ativo === false ? "Inativo" : "Ativo"}
          </span>
          <Switch
            checked={tpl.ativo !== false}
            onCheckedChange={(val) =>
              setTpl((p) => ({ ...p, ativo: val }))
            }
          />
        </div>
      </div>

      <Separator />

      {/* Itens */}
      <div className="space-y-3">
        <div className="flex items-center justify-between">
          <h4 className="font-medium">Itens do checklist</h4>
          <Button
            size="sm"
            onClick={() => {
              setItemEditando(null);
              setAddOpen(true);
            }}
          >
            <Plus className="h-4 w-4 mr-1" />
            Adicionar item
          </Button>
        </div>

        {tpl.itens.length === 0 ? (
          <p className="text-sm text-muted-foreground">
            Nenhum item adicionado. Use “Adicionar item” para começar.
          </p>
        ) : (
          <div className="space-y-2">
            {tpl.itens.map((it) => (
              <div
                key={it.id}
                className="flex items-start justify-between gap-3 p-3 border rounded-lg"
              >
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2">
                    <span className="font-medium truncate">
                      {it.titulo}
                    </span>
                    {it.obrigatorio && (
                      <Badge
                        variant="destructive"
                        className="text-xs"
                      >
                        Obrigatório
                      </Badge>
                    )}
                    {it.categoria && (
                      <Badge
                        variant="outline"
                        className="text-xs"
                      >
                        {it.categoria}
                      </Badge>
                    )}
                  </div>
                  {it.descricao && (
                    <p className="text-sm text-muted-foreground mt-1">
                      {it.descricao}
                    </p>
                  )}
                </div>

                <div className="shrink-0 flex gap-1">
                  <Button
                    variant="outline"
                    size="icon"
                    onClick={() => {
                      setItemEditando(it);
                      setEditItemOpen(true);
                    }}
                    title="Editar item"
                    aria-label="Editar item"
                  >
                    <Edit3 className="h-4 w-4" />
                  </Button>
                  <Button
                    variant="outline"
                    size="icon"
                    className="text-destructive hover:text-destructive"
                    onClick={() => removerItem(it.id)}
                    title="Excluir item"
                    aria-label="Excluir item"
                  >
                    <X className="h-4 w-4" />
                  </Button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Ações – só quando NÃO está em variant="bare" */}
      {variant !== "bare" && (
        <div className="border-t pt-4 flex justify-end gap-2">
          <Button variant="outline" onClick={onCancel}>
            Cancelar
          </Button>
          <Button
            onClick={salvar}
            disabled={!tpl.nome.trim() || tpl.itens.length === 0}
          >
            <Save className="h-4 w-4 mr-1" />
            {editando ? "Salvar alterações" : "Criar checklist"}
          </Button>
        </div>
      )}

      {/* Dialog de item (adicionar/editar) */}
      <ItemDialog
        open={addOpen}
        onOpenChange={setAddOpen}
        onSave={(novo) => adicionarItem(novo)}
        categorias={categorias}
      />

      {itemEditando && (
        <ItemDialog
          open={editItemOpen}
          onOpenChange={(v) => {
            setEditItemOpen(v);
            if (!v) setItemEditando(null);
          }}
          onSave={(novo) =>
            atualizarItem({ ...novo, id: itemEditando.id })
          }
          categorias={categorias}
          initialValue={itemEditando}
        />
      )}
    </div>
  );

  if (variant === "bare") return Content;

  return (
    <Card>
      <CardHeader>
        <CardTitle className="text-base sm:text-lg">
          {editando ? "Editar Checklist" : "Novo Checklist"}
        </CardTitle>
      <CardDescription>
          {editando
            ? "Atualize os campos e salve para aplicar as alterações."
            : "Preencha os campos para criar um novo modelo."}
        </CardDescription>
      </CardHeader>
      <CardContent>{Content}</CardContent>
    </Card>
  );
}

"use client";

import * as React from "react";

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";

import { PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, LabelList, AreaChart, Area } from "recharts";
import {
  ChartContainer,
  ChartTooltip,
  ChartTooltipContent,
  ChartLegend,
  ChartLegendContent,
} from "@/components/ui/chart";

import {
  RefreshCcw,
  TrendingUp,
  Activity,
  Timer,
  DollarSign,
  ClipboardList,
  CheckCircle2,
  CircleAlert,
  UserX,
} from "lucide-react";

import { cn } from "@/lib/utils";

import type { ServiceOrdersDashboardProps } from "../lib/types";
import { obterPeriodoInicial, formatarDataYYYYMMDD, formatarDataCompleta } from "../lib/datas";
import { formatCurrencyBRL, formatDurationHours, formatNumber } from "../lib/format";
import { pickColorForKey } from "../lib/palette";
import { STATIC_ZERO_MONTHS, makeZeroedMonthlyFrom, formatMonthLabel } from "../lib/monthly";
import { useInsights } from "../hooks/use-insights";

import ChartCard from "./chart-card";
import Kpi from "./kpi-ordemservico";
import EmptyState from "./emply-state";
import SheetOsFiltros from "./sheet-os-filtros";

function useMediaQuery(query: string) {
  const [matches, setMatches] = React.useState(false);

  React.useEffect(() => {
    const m = window.matchMedia(query);
    const onChange = () => setMatches(m.matches);
    onChange();
    m.addEventListener("change", onChange);
    return () => m.removeEventListener("change", onChange);
  }, [query]);

  return matches;
}

function abreviarSegundoNome(nome: string) {
  const parts = String(nome ?? "")
    .trim()
    .split(/\s+/)
    .filter(Boolean);

  if (parts.length <= 1) return parts.join(" ");

  const connectors = new Set(["de", "da", "do", "dos", "das", "e"]);
  let idx = 1;
  while (idx < parts.length && connectors.has(parts[idx].toLowerCase())) idx++;
  if (idx >= parts.length) return parts.join(" ");

  const p = parts[idx];
  parts[idx] = p ? `${p[0]}.` : p;
  return parts.join(" ");
}

function encurtarStatusOS(raw: string) {
  const base = String(raw ?? "")
    .trim()
    .replace(/_/g, " ")
    .toUpperCase();

  if (!base) return "";

  const tokenMap: Record<string, string> = {
    AGUARDANDO: "Aguard.",
    CHECKLIST: "Check.",
    APROVACAO: "Aprov.",
    ORCAMENTO: "Orc.",
    EM: "Em",
    ANDAMENTO: "and.",
    CONCLUIDO: "Concl.",
    CANCELADO: "Canc.",
    SEM: "Sem",
    COBRANCA: "cobr.",
  };

  const out = base
    .split(/\s+/)
    .filter(Boolean)
    .map((t) => tokenMap[t] ?? (t.length > 12 ? `${t.slice(0, 12)}.` : t))
    .join(" ");

  return out.length > 18 ? `${out.slice(0, 18)}...` : out;
}

function StatusValueLabelRight(props: any) {
  const { x, y, width, height, value } = props ?? {};
  if (value === undefined || value === null) return null;
  const cx = Number(x ?? 0) + Number(width ?? 0) + 8;
  const cy = Number(y ?? 0) + Number(height ?? 0) / 2 + 4;
  return (
    <text x={cx} y={cy} textAnchor="start" fill="#fff" fontSize={12} fontWeight={400}>
      {value}
    </text>
  );
}

function StatusValueLabelTop(props: any) {
  const { x, y, width, value } = props ?? {};
  if (value === undefined || value === null) return null;
  const cx = Number(x ?? 0) + Number(width ?? 0) / 2;
  const cy = Number(y ?? 0) - 6;
  return (
    <text x={cx} y={cy} textAnchor="middle" fill="#fff" fontSize={12} fontWeight={400}>
      {value}
    </text>
  );
}

export default function ServiceOrdersDashboard({
  className,
  insightsEndpoint = "/api/ordens/insights",
  autoRefreshMs,
}: ServiceOrdersDashboardProps) {
  const isMobile = useMediaQuery("(max-width: 640px)");

  const periodoInicial = React.useMemo(obterPeriodoInicial, []);
  const [dataInicio, setDataInicio] = React.useState<Date | null>(periodoInicial.inicio);
  const [dataFim, setDataFim] = React.useState<Date | null>(periodoInicial.fim);
  const [filtroAberto, setFiltroAberto] = React.useState(false);

  const endpointComFiltro = React.useMemo(() => {
    if (!dataInicio || !dataFim) return insightsEndpoint;
    const params = new URLSearchParams({
      dateFrom: formatarDataYYYYMMDD(dataInicio),
      dateTo: formatarDataYYYYMMDD(dataFim),
    });
    return `${insightsEndpoint}?${params.toString()}`;
  }, [insightsEndpoint, dataInicio, dataFim]);

  const { data, loading, error, refetch } = useInsights(endpointComFiltro, autoRefreshMs);

  const textoPeriodo =
    dataInicio && dataFim
      ? `${formatarDataCompleta(dataInicio)} - ${formatarDataCompleta(dataFim)}`
      : "Período não definido";

  function tratarDataInicio(date?: Date) {
    if (!date) return setDataInicio(null);
    if (dataFim && date > dataFim) setDataFim(date);
    setDataInicio(date);
  }

  function tratarDataFim(date?: Date) {
    if (!date) return setDataFim(null);
    if (dataInicio && date < dataInicio) setDataInicio(date);
    setDataFim(date);
  }

  function limparFiltros() {
    const p = obterPeriodoInicial();
    setDataInicio(p.inicio);
    setDataFim(p.fim);
  }

  // Base de 12 meses "zerados" para montar as séries
  const [zeroMonths, setZeroMonths] = React.useState<string[]>(STATIC_ZERO_MONTHS);
  React.useEffect(() => {
    setZeroMonths(makeZeroedMonthlyFrom(new Date(), 12));
  }, []);

  const monthly = React.useMemo(() => {
    const newMap = new Map((data?.monthlyNew ?? []).map((x) => [x.month, x.count]));
    const doneMap = new Map((data?.monthlyCompleted ?? []).map((x) => [x.month, x.count]));
    const revMap = new Map((data?.monthlyRevenue ?? []).map((x) => [x.month, x.amount]));

    const base = zeroMonths.map((m) => ({ month: m, label: formatMonthLabel(m) }));

    return {
      new: base.map(({ month, label }) => ({ label, count: newMap.get(month) ?? 0 })),
      done: base.map(({ month, label }) => ({ label, count: doneMap.get(month) ?? 0 })),
      rev: base.map(({ month, label }) => ({ label, amount: revMap.get(month) ?? 0 })),
    };
  }, [data, zeroMonths]);

  const seriesNewDone = (monthly.new ?? []).map((n, i) => ({
    label: n.label,
    new: n.count,
    done: (monthly.done ?? [])[i]?.count ?? 0,
  }));

  const statusKeys = React.useMemo(() => Object.keys(data?.countsByStatus ?? {}), [data?.countsByStatus]);

  // mantém como no seu original (não vamos usar para colorir, mas deixa disponível)
  const statusItems = (statusKeys.length ? statusKeys : []).map((name) => ({
    name,
    value: data?.countsByStatus?.[name] ?? 0,
    fill: pickColorForKey(name),
  }));

  const prioEntries = Object.entries(data?.countsByPriority ?? {}).filter(([, v]) => Number(v) > 0);
  const prioItems = prioEntries.map(([key, value]) => ({
    key,
    value: Number(value) || 0,
    color: pickColorForKey(key),
  }));

  const servicesByUser = data?.servicesByUser ?? [];
  const servicesByUserSorted = React.useMemo(() => {
    return [...servicesByUser].sort((a, b) => b.totalServicos - a.totalServicos);
  }, [servicesByUser]);

  // Altura dinamica para permitir scroll quando ha muitos usuarios.
  const servicesByUserChartHeight = React.useMemo(() => {
    const rowH = 38; // altura aproximada por usuario na barra horizontal
    const n = servicesByUserSorted.length || 1;
    return Math.max(220, n * rowH);
  }, [servicesByUserSorted.length]);

  const total = data?.totalOrders ?? 0;
  const open = data?.ordersOpen ?? 0;
  const completed = data?.ordersCompleted ?? 0;
  const avgHrs = data?.avgCompletionHours ?? 0;

  // novo: serviços sem realizador (padrão novo)
  const servicesWithoutRealizador = (data as any)?.servicesWithoutRealizador ?? 0;

  // altura dinâmica só para quando ficar vertical no mobile
  const statusChartHeight = React.useMemo(() => {
    const n = statusItems.length || 1;
    return Math.max(220, n * 38);
  }, [statusItems.length]);

  return (
    <Card className={cn("w-full", className)}>
      <CardHeader className="flex flex-row items-start justify-between gap-2">
        <div className="space-y-1">
          <CardTitle className="flex items-center gap-2">
            <ClipboardList className="h-5 w-5" aria-hidden="true" />
            Dashboard de Ordens de Serviço
          </CardTitle>

          <CardDescription className="text-xs sm:text-sm">
            Visão executiva de produtividade, prazos e receita.
          </CardDescription>

          <Badge variant="default" className="text-[10px] sm:text-xs">
            Período: {textoPeriodo}
          </Badge>
        </div>

        <div className="flex flex-wrap items-center justify-end gap-2 sm:gap-3">
          <SheetOsFiltros
            aberto={filtroAberto}
            aoMudarAberto={setFiltroAberto}
            dataInicio={dataInicio}
            dataFim={dataFim}
            aoMudarDataInicio={tratarDataInicio}
            aoMudarDataFim={tratarDataFim}
            aoLimpar={limparFiltros}
          />

          {autoRefreshMs ? (
            <Badge variant="secondary" className="whitespace-nowrap text-[10px] sm:text-xs">
              Auto · {Math.round((autoRefreshMs ?? 0) / 1000)}s
            </Badge>
          ) : null}

          <Button
            variant="outline"
            size="icon"
            onClick={refetch}
            aria-label="Atualizar dados"
            className={cn("h-8 w-8 sm:h-9 sm:w-9", loading && "cursor-wait opacity-80")}
          >
            <RefreshCcw className={cn("h-3.5 w-3.5", loading && "animate-spin")} aria-hidden="true" />
          </Button>
        </div>
      </CardHeader>

      <CardContent className="space-y-6">
        {/* KPIs */}
        <div className="grid grid-cols-2 gap-4 lg:grid-cols-7">
          <Kpi icon={ClipboardList} label="Total de OS" value={formatNumber(total)} />
          <Kpi icon={Activity} label="OS do dia" value={formatNumber(data?.ordersToday ?? 0)} />
          <Kpi icon={CheckCircle2} label="Concluídas" value={formatNumber(completed)} />
          <Kpi icon={CircleAlert} label="Em andamento" value={formatNumber(open)} />
          <Kpi icon={Timer} label="Tempo médio" value={formatDurationHours(avgHrs)} />
          <Kpi icon={DollarSign} label="Receita (30d)" value={formatCurrencyBRL(data?.revenue30d ?? 0)} />
          <Kpi icon={UserX} label="Serviços sem realizador" value={formatNumber(servicesWithoutRealizador)} />
        </div>

        {error && !loading ? (
          <div className="rounded-lg border border-destructive/50 bg-destructive/10 p-3 text-sm">
            Erro ao carregar insights: <span className="font-medium">{error}</span>
          </div>
        ) : null}

        <div className="flex w-full flex-col gap-6 md:grid md:grid-cols-2 xl:grid-cols-3">
          {/* OS por mês */}
          <ChartCard
            title="OS por mês"
            description="Novas vs Concluídas (12m)"
            badge="Tendência"
            badgeIcon={<TrendingUp className="h-3.5 w-3.5" />}
            className="md:col-span-2 xl:col-span-2"
          >
            <ChartContainer
              config={{
                new: { label: "Novas", color: "hsl(var(--chart-1))" },
                done: { label: "Concluídas", color: "hsl(var(--chart-2))" },
              }}
              className="h-48 w-full xs:h-56 sm:h-64 md:h-72 lg:h-80"
            >
              <AreaChart data={seriesNewDone} margin={{ top: 12, right: 12, left: -20, bottom: 0 }}>
                <defs>
                  <linearGradient id="areaNew" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="rgb(43, 127, 255)" stopOpacity={0.25} />
                    <stop offset="95%" stopColor="rgb(43, 127, 255)" stopOpacity={0} />
                  </linearGradient>
                  <linearGradient id="areaDone" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="rgba(255, 210, 0, 0.8)" stopOpacity={0.25} />
                    <stop offset="95%" stopColor="rgba(255, 210, 0, 0.8)" stopOpacity={0} />
                  </linearGradient>
                </defs>

                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="hsl(var(--border))" />
                <XAxis
                  dataKey="label"
                  axisLine={false}
                  tickLine={false}
                  fontSize={12}
                  tickMargin={8}
                  stroke="hsl(var(--muted-foreground))"
                />
                <YAxis
                  allowDecimals={false}
                  axisLine={false}
                  tickLine={false}
                  fontSize={12}
                  tickMargin={8}
                  stroke="hsl(var(--muted-foreground))"
                />

                <ChartTooltip content={<ChartTooltipContent indicator="line" />} />

                <Area
                  type="monotone"
                  dataKey="new"
                  stroke="rgb(43, 127, 255)"
                  fill="url(#areaNew)"
                  strokeWidth={2}
                  dot={false}
                />
                <Area
                  type="monotone"
                  dataKey="done"
                  stroke="rgba(255, 210, 0, 0.8)"
                  fill="url(#areaDone)"
                  strokeWidth={2}
                  dot={false}
                />

                <ChartLegend content={<ChartLegendContent />} />
              </AreaChart>
            </ChartContainer>
          </ChartCard>

          {/* Serviços por usuário */}
          <ChartCard
            title="Serviços por usuário"
            description="Ranking de serviços concluídos no período"
            badge="Ranking"
            className="md:col-span-2 xl:col-span-1"
          >
            <div className="max-h-60 overflow-y-auto pr-1 sm:max-h-80">
              <ChartContainer
                config={{
                  // ChartContainer injeta `--color-${key}`; usamos isso no `fill` do Bar.
                  totalServicos: { label: "Serviços", color: "hsl(var(--chart-3))" },
                }}
                className="w-full"
                style={{ height: servicesByUserChartHeight }}
              >
                <BarChart
                  accessibilityLayer
                  data={servicesByUserSorted}
                  layout="vertical"
                  margin={{ top: 8, right: 16, left: 0, bottom: 8 }}
                  barSize={18}
                >
                  <CartesianGrid horizontal={false} stroke="hsl(var(--border))" />

                  <XAxis
                    type="number"
                    allowDecimals={false}
                    axisLine={false}
                    tickLine={false}
                    fontSize={12}
                    tickMargin={8}
                    stroke="hsl(var(--muted-foreground))"
                  />

                  <YAxis
                    type="category"
                    dataKey="usuarioNome"
                    axisLine={false}
                    tickLine={false}
                    fontSize={12}
                    width={90}
                    tickFormatter={(v) => {
                      const s = abreviarSegundoNome(String(v ?? ""));
                      const max = isMobile ? 14 : 18;
                      return s.length > max ? `${s.slice(0, max)}...` : s;
                    }}
                    stroke="hsl(var(--muted-foreground))"
                  />

                  <ChartTooltip cursor={false} content={<ChartTooltipContent hideLabel />} />

                  <Bar
                    dataKey="totalServicos"
                    radius={[0, 4, 4, 0]}
                    fill="rgba(43, 127, 255, 0.4)"
                    stroke="rgb(43, 127, 255)"
                    strokeWidth={2}
                  >
                    <LabelList dataKey="totalServicos" position="right" className="fill-foreground" fontSize={12} />
                  </Bar>
                </BarChart>
              </ChartContainer>
            </div>
          </ChartCard>

          {/* OS por status (muda orientação só no mobile) */}
          <ChartCard title="OS por status" description="Distribuição atual" badge="Barras" className="md:col-span-2">
            <div className="w-full" style={{ height: isMobile ? statusChartHeight : 280 }}>
              <ChartContainer
                config={{
                  value: { label: "Quantidade de Ordens", color: "hsl(var(--chart-1))" },
                }}
                className="h-full w-full"
              >
                {isMobile ? (
                  <BarChart
                    data={statusItems}
                    layout="vertical"
                    margin={{ top: 8, right: 16, left: -20, bottom: 8 }}
                    barSize={14}
                  >
                    <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="hsl(var(--border))" />

                    <XAxis
                      type="number"
                      allowDecimals={false}
                      axisLine={false}
                      tickLine={false}
                      fontSize={12}
                      tickMargin={8}
                      stroke="hsl(var(--muted-foreground))"
                    />

                    <YAxis
                      type="category"
                      dataKey="name"
                      axisLine={false}
                      tickLine={false}
                      fontSize={12}
                      width={120}
                      tickFormatter={encurtarStatusOS}
                      stroke="hsl(var(--muted-foreground))"
                    />

                    <ChartTooltip content={<ChartTooltipContent indicator="dashed" />} />

                    <Bar dataKey="value" radius={[0, 6, 6, 0]}>
                      {statusItems.map((s) => (
                        <Cell key={s.name} fill="rgba(43, 127, 255, 0.3)" stroke="rgb(43, 127, 255)" strokeWidth={2} />
                      ))}
                      <LabelList dataKey="value" position="right" content={<StatusValueLabelRight />} />
                    </Bar>

                    <ChartLegend content={<ChartLegendContent />} />
                  </BarChart>
                ) : (
                  <BarChart data={statusItems} margin={{ top: 20, right: 20, left: 0, bottom: 0 }} barSize={50}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="hsl(var(--border))" />

                    <XAxis
                      dataKey="name"
                      axisLine={false}
                      tickLine={false}
                      fontSize={12}
                      tickMargin={8}
                      tickFormatter={encurtarStatusOS}
                      stroke="hsl(var(--muted-foreground))"
                    />

                    <YAxis
                      allowDecimals={false}
                      axisLine={false}
                      tickLine={false}
                      fontSize={12}
                      tickMargin={8}
                      stroke="hsl(var(--muted-foreground))"
                    />

                    <ChartTooltip content={<ChartTooltipContent indicator="dashed" />} />

                    <Bar dataKey="value" radius={[6, 6, 0, 0]}>
                      {statusItems.map((s) => (
                        <Cell key={s.name} fill="rgba(43, 127, 255, 0.3)" stroke="rgb(43, 127, 255)" strokeWidth={2} />
                      ))}
                      <LabelList dataKey="value" position="top" content={<StatusValueLabelTop />} />
                    </Bar>

                    <ChartLegend content={<ChartLegendContent />} />
                  </BarChart>
                )}
              </ChartContainer>
            </div>
          </ChartCard>

          {/* Prioridade (pizza) - mantém exatamente as cores originais (azul) */}
          <ChartCard
            title="Prioridade das OS"
            description="Carga por nível"
            badge="Pizza"
            className="md:col-span-2 xl:col-span-1"
          >
            <ChartContainer
              config={Object.fromEntries(prioItems.map((p) => [p.key, { label: p.key, color: p.color }]))}
              className="w-full h-52 sm:h-60 md:h-72"
            >
              <PieChart>
                <ChartTooltip content={<ChartTooltipContent hideLabel />} />
                <Pie
                  data={prioItems}
                  dataKey="value"
                  nameKey="key"
                  innerRadius="55%"
                  outerRadius="80%"
                  paddingAngle={4}
                  strokeWidth={2}
                >
                  {prioItems.map((p) => (
                    <Cell key={p.key} fill="rgba(43, 127, 255, 0.3)" stroke="rgb(43, 127, 255)" strokeWidth={2} />
                  ))}
                  <LabelList
                    dataKey="value"
                    position="outside"
                    className="fill-foreground"
                    fontSize={12}
                    stroke="none"
                    formatter={(label: React.ReactNode) => {
                      const v = Number(label ?? 0);
                      return v > 0 ? String(v) : "";
                    }}
                  />
                </Pie>
                <ChartLegend content={<ChartLegendContent nameKey="key" />} />
              </PieChart>
            </ChartContainer>
          </ChartCard>
        </div>

        {!loading && !error && total === 0 ? <EmptyState /> : null}
      </CardContent>
    </Card>
  );
}

"use client";

import {
DialogClose,
DialogContent,
DialogDescription,
DialogFooter,
DialogHeader,
DialogTitle,
} from "@/components/ui/dialog";
import { useEffect,useMemo,useState } from "react";
import { toast } from "sonner";

import FornecedorSelect from "@/app/(app)/components/fornecedorSelect";
import ProductSelect from "@/app/(app)/components/productSelect";

import { Fornecedor,Produto,Unidade_medida } from "../../types";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
Select,
SelectContent,
SelectItem,
SelectTrigger,
SelectValue,
} from "@/components/ui/select";
import { Separator } from "@/components/ui/separator";
import formatarEmReal from "@/utils/formatarEmReal";
import { Loader2,Search } from "lucide-react";

export const TIPOS_ENTRADA = [
  { value: "COMPRA_FORNECEDOR", label: "Compra fornecedor" },
  { value: "COMPRA_PF", label: "Compra PF" },
  { value: "DEVOLUCAO", label: "Devolução" },
] as const;

export type EntradaTipo = (typeof TIPOS_ENTRADA)[number]["value"];

type EntradaItemEditForm = {
  id?: number; // <- existe quando já está no banco
  produto_id: number;

  titulo: string | null;
  referencia: string | null;

  ncm: string | null;
  csosn: string | null;
  cfop: string | null;
  cest: string | null;
  unidade: Unidade_medida | null;

  cClassTrib: string | null;
  cstIbs: string | null;
  cstCbs: string | null;

  cst: string | null;
  aliquotaicms: number | null;

  cst_pis: string | null;
  aliquota_pis: number | null;

  cst_cofins: string | null;
  aliquota_cofins: number | null;

  quantidade: number;
  precovenda: number;
};

function n(v: unknown, fallback = 0) {
  const x = typeof v === "number" ? v : Number(v);
  return Number.isFinite(x) ? x : fallback;
}

function toNullableText(v: unknown): string | null {
  if (v === undefined || v === null) return null;
  const s = String(v).trim();
  return s.length ? s : null;
}

function criarItemDeProduto(produto: Produto): EntradaItemEditForm {
  return {
    produto_id: produto.id ?? 0,

    titulo:
      toNullableText((produto as any).titulo) ??
      toNullableText((produto as any).descricao) ??
      null,
    referencia: toNullableText((produto as any).referencia),

    ncm: toNullableText((produto as any).ncm),
    csosn: toNullableText((produto as any).csosn),
    cfop: toNullableText((produto as any).cfop),
    cest: toNullableText((produto as any).cest),
    unidade: ((produto as any).unidade ?? null) as Unidade_medida | null,

    cClassTrib: toNullableText((produto as any).cClassTrib),
    cstIbs: toNullableText((produto as any).cstIbs),
    cstCbs: toNullableText((produto as any).cstCbs),

    cst: toNullableText((produto as any).cst),
    aliquotaicms:
      (produto as any).aliquotaicms == null ? null : n((produto as any).aliquotaicms),

    cst_pis: toNullableText((produto as any).cst_pis),
    aliquota_pis:
      (produto as any).aliquota_pis == null ? null : n((produto as any).aliquota_pis),

    cst_cofins: toNullableText((produto as any).cst_cofins),
    aliquota_cofins:
      (produto as any).aliquota_cofins == null ? null : n((produto as any).aliquota_cofins),

    quantidade: 1,
    precovenda: n((produto as any).precovenda, 0),
  };
}

interface EditContentProps {
  selectedEntradaId?: number;
  open?: boolean; // <- passe o open do Dialog aqui
  onSaved?: () => void;
}

export default function EditContent({ selectedEntradaId, onSaved }: EditContentProps) {

  // loading já começa TRUE quando abrir (se tiver id)
  const [loadingEntrada, setLoadingEntrada] = useState<boolean>(true)

  const [saving, setSaving] = useState(false);

  const [tipo, setTipo] = useState<EntradaTipo>("COMPRA_FORNECEDOR");
  const [itens, setItens] = useState<EntradaItemEditForm[]>([]);
  const [itensRemover, setItensRemover] = useState<number[]>([]);

  const [fornecedorSelecionado, setFornecedorSelecionado] = useState<
    Fornecedor | undefined
  >(undefined);

  const [openFornecedor, setOpenFornecedor] = useState(false);
  const [openProduto, setOpenProduto] = useState(false);

  const totalGeral = useMemo(() => {
    return itens.reduce((acc, it) => acc + n(it.quantidade) * n(it.precovenda), 0);
  }, [itens]);

  const updateItem = <K extends keyof EntradaItemEditForm>(
    index: number,
    key: K,
    value: EntradaItemEditForm[K]
  ) => {
    setItens((prev) => {
      const copy = [...prev];
      copy[index] = { ...copy[index], [key]: value } as EntradaItemEditForm;
      return copy;
    });
  };

  const handleAdicionarProduto = (produto: Produto) => {
    setItens((prev) => {
      const pid = produto.id ?? 0;
      const idx = prev.findIndex((i) => i.produto_id === pid);
      if (idx >= 0) {
        const copy = [...prev];
        const item = { ...copy[idx] };
        item.quantidade = n(item.quantidade) + 1;
        copy[idx] = item;
        return copy;
      }
      return [...prev, criarItemDeProduto(produto)];
    });
  };

  const handleGetEntrada = async (id: number, signal?: AbortSignal) => {
    setLoadingEntrada(true);
    try {
      const res = await fetch(`/api/entradas/${id}`, { method: "GET", signal });
      if (!res.ok) {
        const msg = await res.text();
        throw new Error(msg || "Falha ao buscar entrada.");
      }

      const json = await res.json();
      const entrada = json?.entrada;
      if (!entrada) throw new Error("Resposta inválida da API (sem 'entrada').");

      setTipo((entrada.tipo as EntradaTipo) ?? "COMPRA_FORNECEDOR");
      setFornecedorSelecionado(entrada.fornecedor ?? undefined);

      const itensApi = Array.isArray(entrada.itens) ? entrada.itens : [];
      const itensForm: EntradaItemEditForm[] = itensApi.map((it: any) => ({
        id: it.id != null ? Number(it.id) : undefined,
        produto_id: Number(it.produto_id),

        titulo: toNullableText(it.titulo),
        referencia: toNullableText(it.referencia),

        ncm: toNullableText(it.ncm),
        csosn: toNullableText(it.csosn),
        cfop: toNullableText(it.cfop),
        cest: toNullableText(it.cest),
        unidade: (it.unidade ?? null) as Unidade_medida | null,

        cClassTrib: toNullableText(it.cClassTrib ?? it["cClassTrib"]),
        cstIbs: toNullableText(it.cstIbs ?? it["cstIbs"]),
        cstCbs: toNullableText(it.cstCbs ?? it["cstCbs"]),

        cst: toNullableText(it.cst),
        aliquotaicms: it.aliquotaicms == null ? null : n(it.aliquotaicms),

        cst_pis: toNullableText(it.cst_pis),
        aliquota_pis: it.aliquota_pis == null ? null : n(it.aliquota_pis),

        cst_cofins: toNullableText(it.cst_cofins),
        aliquota_cofins: it.aliquota_cofins == null ? null : n(it.aliquota_cofins),

        quantidade: n(it.quantidade, 1),
        precovenda: n(it.precovenda, 0),
      }));

      setItens(itensForm);
      setItensRemover([]);
    } catch (err: any) {
      if (err?.name === "AbortError") return;
      console.log(err);
      toast.error("Erro ao carregar entrada.");
    } finally {
      setLoadingEntrada(false);
    }
  };

  const handleSalvarEdicao = async () => {
    if (!selectedEntradaId) return;

    if (!fornecedorSelecionado) {
      toast.error("Selecione um fornecedor antes de salvar.");
      return;
    }

    if (itens.length === 0) {
      toast.error("A entrada precisa ter ao menos 1 item.");
      return;
    }

    setSaving(true);
    try {
      const payload = {
        entrada: {
          fornecedorid: fornecedorSelecionado.id ?? null,
          tipo,
        },
        itens: itens.map((it) => ({
          id: it.id,
          produto_id: it.produto_id,

          unidade: it.unidade,
          quantidade: n(it.quantidade),
          precovenda: n(it.precovenda),

          ncm: it.ncm,
          cest: it.cest,
          csosn: it.csosn,
          referencia: it.referencia,
          titulo: it.titulo,

          cClassTrib: it.cClassTrib,
          cstIbs: it.cstIbs,
          cstCbs: it.cstCbs,

          cst: it.cst,
          aliquotaicms: it.aliquotaicms,
          cfop: it.cfop,

          cst_pis: it.cst_pis,
          aliquota_pis: it.aliquota_pis,

          cst_cofins: it.cst_cofins,
          aliquota_cofins: it.aliquota_cofins,
        })),
        itensRemover,
      };

      const res = await fetch(`/api/entradas/${selectedEntradaId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (!res.ok) {
        const msg = await res.text();
        console.log("Erro PATCH:", msg);
        toast.error("Erro ao salvar alterações.");
        return;
      }

      const data = await res.json();
      const entradaAtualizada = data?.entrada;

      // Re-hidrata com retorno (principalmente ids de itens novos)
      if (entradaAtualizada) {
        setTipo((entradaAtualizada.tipo as EntradaTipo) ?? tipo);
        setFornecedorSelecionado(entradaAtualizada.fornecedor ?? fornecedorSelecionado);

        const itensApi = Array.isArray(entradaAtualizada.itens) ? entradaAtualizada.itens : [];
        setItens(
          itensApi.map((it: any) => ({
            id: it.id != null ? Number(it.id) : undefined,
            produto_id: Number(it.produto_id),

            titulo: toNullableText(it.titulo),
            referencia: toNullableText(it.referencia),

            ncm: toNullableText(it.ncm),
            csosn: toNullableText(it.csosn),
            cfop: toNullableText(it.cfop),
            cest: toNullableText(it.cest),
            unidade: (it.unidade ?? null) as Unidade_medida | null,

            cClassTrib: toNullableText(it.cClassTrib ?? it["cClassTrib"]),
            cstIbs: toNullableText(it.cstIbs ?? it["cstIbs"]),
            cstCbs: toNullableText(it.cstCbs ?? it["cstCbs"]),

            cst: toNullableText(it.cst),
            aliquotaicms: it.aliquotaicms == null ? null : n(it.aliquotaicms),

            cst_pis: toNullableText(it.cst_pis),
            aliquota_pis: it.aliquota_pis == null ? null : n(it.aliquota_pis),

            cst_cofins: toNullableText(it.cst_cofins),
            aliquota_cofins: it.aliquota_cofins == null ? null : n(it.aliquota_cofins),

            quantidade: n(it.quantidade, 1),
            precovenda: n(it.precovenda, 0),
          }))
        );

        setItensRemover([]);
      }

      toast.success("Alterações salvas!");
      onSaved?.();
      handleGetEntrada(selectedEntradaId);
    } finally {
      setSaving(false);
    }
  };

  /**
   * Carrega antes de “pintar” quando o dialog abrir:
   * - garante o loading imediatamente na abertura
   * - evita 1 frame mostrando conteúdo velho
   */
  useEffect(() => {
    if (selectedEntradaId) {
      handleGetEntrada(selectedEntradaId)
    }
  }, [])

  if (loadingEntrada) {
    return (
      <DialogContent className="h-dvh min-w-screen p-0 overflow-hidden sm:max-w-[1100px] sm:max-h-[850px] sm:w-[95vw] sm:min-w-0">
        <DialogHeader className="hidden">
          <DialogTitle></DialogTitle>
        </DialogHeader>
        <div className="flex h-full min-h-0 flex-col justify-center items-center">
          <div className="size-8 border-t-2 border-primary rounded-t-full animate-spin"></div>
          <span className="text-primary">Carregando</span>
        </div>
      </DialogContent>
    );
  }

  return (
    <DialogContent className="h-svh min-w-screen p-0 overflow-hidden sm:max-w-[1100px] sm:max-h-[850px] sm:w-[95vw] sm:min-w-0">
      <div className="flex h-full min-h-0 flex-col">
        <DialogHeader className="shrink-0 px-6 py-4 border-b">
          <DialogTitle>Entrada #{selectedEntradaId}</DialogTitle>
          <DialogDescription>
            Edite os itens da entrada
          </DialogDescription>
        </DialogHeader>

        <FornecedorSelect
          OnSelect={(f) => {
            setFornecedorSelecionado(f);
            setOpenFornecedor(false);
          }}
          open={openFornecedor}
          setOpen={setOpenFornecedor}
        />

        <ProductSelect
          OnSelect={(p) => {
            handleAdicionarProduto(p);
            setOpenProduto(false);
          }}
          open={openProduto}
          setOpen={setOpenProduto}
        />

        <div className="h-full min-h-0 overflow-auto dark:bg-muted-foreground/5 px-6 py-6 space-y-4">
          {/* Dados da entrada */}
          <div className="border rounded-xl p-4 space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="space-y-2">
                <Label>Tipo da entrada</Label>
                <Select value={tipo} onValueChange={(v) => setTipo(v as EntradaTipo)}>
                  <SelectTrigger className="w-full text-xs">
                    <SelectValue placeholder="Selecione o tipo" />
                  </SelectTrigger>
                  <SelectContent className="text-xs">
                    {TIPOS_ENTRADA.map((opt) => (
                      <SelectItem
                        key={opt.value}
                        value={opt.value}
                        className="text-xs hover:cursor-pointer"
                      >
                        {opt.label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            <Separator />

            <div className="space-y-2">
              <Label>Fornecedor</Label>

              {fornecedorSelecionado ? (
                <div className="flex flex-row items-center gap-2">
                  <div className="px-2 py-1 rounded-xl bg-muted text-xs">
                    <span className="font-medium text-muted-foreground">
                      #{fornecedorSelecionado.id}
                    </span>{" "}
                    <span className="text-primary">
                      {fornecedorSelecionado?.nomerazaosocial}
                    </span>
                  </div>
                  {/* <div
                    onClick={() => setFornecedorSelecionado(undefined)}
                    className="rounded-full p-1.5 bg-muted hover:cursor-pointer"
                    title="Remover fornecedor"
                  >
                    <X className="text-red-500 w-3 h-3" />
                  </div> */}
                </div>
              ) : (
                <div className="flex flex-row items-center gap-2 text-sm text-muted-foreground">
                  <span>Nenhum fornecedor selecionado</span>
                  <div
                    onClick={() => setOpenFornecedor(true)}
                    className="group p-1.5 rounded-full bg-muted/50 hover:bg-muted transition-all hover:cursor-pointer"
                    title="Selecionar fornecedor"
                  >
                    <Search className="w-3 h-3 text-primary/80 group-hover:text-primary transition-all" />
                  </div>
                </div>
              )}
            </div>

            <Separator />

            <div className="space-y-2">
              <Label>Produtos</Label>
              {/* 
              <div className="flex items-center gap-2">
                <Button
                  variant="outline"
                  type="button"
                  size="sm"
                  className="gap-2 text-xs hover:cursor-pointer"
                  onClick={() => setOpenProduto(true)}
                >
                  <Search className="h-3 w-3" />
                  Adicionar produto
                </Button>

                <Button
                  type="button"
                  variant="ghost"
                  className="gap-2 text-xs hover:cursor-pointer"
                  size="sm"
                  onClick={() => {
                    const idsExistentes = itens
                      .map((i) => i.id)
                      .filter((x): x is number => typeof x === "number");
                    setItensRemover((r) => Array.from(new Set([...r, ...idsExistentes])));
                    setItens([]);
                  }}
                  disabled={itens.length === 0}
                >
                  Limpar lista
                </Button>
              </div> */}
            </div>

            <Separator />

            <div className="rounded-lg border p-3 space-y-2">
              <div className="flex items-center justify-between text-sm">
                <span className="text-muted-foreground">Itens</span>
                <span className="font-medium">{itens.length}</span>
              </div>
              <div className="flex items-center justify-between text-sm">
                <span className="text-muted-foreground">Total</span>
                <span className="font-semibold">
                  {formatarEmReal(Number(totalGeral.toFixed(2)))}
                </span>
              </div>
            </div>
          </div>

          {/* Lista de itens */}
          <div className="border rounded-xl p-4 min-h-0">
            <div className="flex items-center justify-between mb-3">
              <div>
                <h3 className="text-sm font-semibold">Itens da entrada</h3>
                <p className="text-xs text-muted-foreground">
